-- Simulado
INSERT INTO simulados (id, title, description) VALUES ('00000000-0000-0000-0000-000000000001', 'Simulado Resolvido - Amostra', 'Simulado amostra com 20 questões de Direito Constitucional, Administrativo, Processual e Direitos Humanos');

-- Questões e Alternativas

-- Q1: Constitucionalismo e Movimentos Constitucionais
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000001-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Constitucionalismo e Movimentos Constitucionais'),
  1,
  'multiple_choice',
  'Em um curso preparatório para a magistratura, os alunos analisavam a evolução histórica do constitucionalismo e sua relação com a limitação do poder político. Durante o debate, alguns participantes defenderam que somente os Estados que adotaram Constituições escritas, rígidas e dotadas de controle jurisdicional poderiam ser considerados verdadeiramente constitucionais. Outros, porém, sustentaram que a experiência constitucional não se restringe ao modelo moderno, havendo formas históricas distintas de contenção do poder político, ainda que sem textos constitucionais codificados. O professor, então, apresentou diferentes experiências históricas: (i) sociedades da Antiguidade que já impunham limites religiosos, morais ou consuetudinários ao exercício do poder; (ii) o constitucionalismo inglês, construído de maneira gradual, por meio de documentos e costumes; e (iii) o constitucionalismo moderno, surgido no século XVIII, marcado pela adoção de Constituições escritas e pela consagração explícita de direitos fundamentais e da separação dos poderes. Considerando a ideia de constitucionalismo como fenômeno histórico plural, bem como as contribuições doutrinárias de autores como J. J. Gomes Canotilho, Karl Loewenstein e Dirley da Cunha Jr., assinale a alternativa correta.',
  'C',
  'O constitucionalismo deve ser compreendido como um fenômeno histórico complexo e plural, que não se limita à adoção de Constituições escritas nem se esgota no modelo jurídico-político inaugurado no século XVIII. Trata-se, na realidade, de um conjunto de experiências históricas, desenvolvidas em diferentes contextos sociais, culturais e políticos, cujo traço comum reside na busca pela limitação do poder estatal e pela proteção da liberdade humana frente à arbitrariedade dos governantes. Autores como J. J. Gomes Canotilho destacam, com precisão, que é mais adequado falar em “movimentos constitucionais”, justamente porque a ideia de submeter o poder político a limites não surgiu de forma uniforme nem simultânea em todos os Estados. Antes mesmo do constitucionalismo moderno, já se verificavam experiências constitucionais em sentido material, como no constitucionalismo hebreu, apontado por Karl Loewenstein, no qual o poder encontrava limites de natureza religiosa e moral, bem como nas experiências da Antiguidade Clássica, especialmente em Atenas e Roma, que desenvolveram formas institucionais de contenção do exercício do poder. No período medieval, o constitucionalismo inglês assume papel relevante, não por meio de um texto constitucional codificado, mas a partir de um processo histórico gradual, marcado por documentos como a Magna Carta, pelo fortalecimento do Parlamento e pela consolidação de costumes que limitaram o poder monárquico. Essa experiência demonstra que a existência de uma Constituição escrita não é condição necessária para o reconhecimento de constitucionalismo em sentido material, desde que haja mecanismos efetivos de controle do poder político. Somente com o constitucionalismo moderno, a partir do século XVIII, especialmente após as Revoluções Americana e Francesa, é que se consolida a ideia de Constituição escrita, rígida e suprema, concebida como instrumento racional de organização do Estado, de separação dos poderes e de proteção explícita dos direitos fundamentais. Essa ruptura com o absolutismo não cria o constitucionalismo, mas inaugura uma nova técnica de sua realização. Nesse sentido, conforme enfatiza Dirley da Cunha Jr., o constitucionalismo está intrinsecamente ligado à noção de Constituição como instrumento destinado a concretizar o ideal de liberdade humana, por meio da criação de instituições capazes de limitar e controlar o poder político. Tal compreensão afasta visões reducionistas que identificam o constitucionalismo exclusivamente com a existência de um texto constitucional formal, reafirmando que seu núcleo essencial reside na contenção do poder e na garantia de direitos. Essa concepção encontra expressão simbólica no art. 16 da Declaração dos Direitos do Homem e do Cidadão de 1789, ao afirmar que não há Constituição onde não estejam asseguradas a garantia dos direitos e a separação dos poderes. O que se evidencia, portanto, é que o constitucionalismo não se define pela forma, mas pela finalidade: limitar o poder estatal e proteger os governados contra o arbítrio.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000001-0000-0000-0000-000000000000', 'A', 'O constitucionalismo somente se caracteriza a partir do século XVIII, com a adoção de Constituições escritas e rígidas, sendo inadequado reconhecer experiências constitucionais anteriores, por inexistirem mecanismos jurídicos formais de limitação do poder.', 'Reduz o constitucionalismo ao modelo moderno, ignorando experiências históricas relevantes de limitação do poder político, como o constitucionalismo hebreu, grego e inglês, que operavam por meios consuetudinários, religiosos ou institucionais, ainda que sem Constituição escrita.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000001-0000-0000-0000-000000000000', 'B', 'O constitucionalismo antigo e o constitucionalismo moderno compartilham a mesma estrutura jurídica, diferenciando-se apenas quanto à extensão dos direitos fundamentais assegurados aos governados.', 'Confunde constitucionalismo antigo e moderno como se possuíssem a mesma estrutura jurídica. No constitucionalismo antigo, os limites ao poder decorriam de costumes, pactos e direitos estamentais; no moderno, há ruptura com o absolutismo e adoção consciente de Constituições escritas, supremas e estruturantes do poder.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000001-0000-0000-0000-000000000000', 'C', 'O constitucionalismo pode ser compreendido como um conjunto de movimentos históricos distintos, desenvolvidos em épocas e contextos diversos, mas convergentes na finalidade de limitar o poder político e assegurar a liberdade, ainda que por técnicas diferentes.', 'Reconhece o constitucionalismo como um fenômeno plural, formado por diferentes movimentos históricos, políticos e culturais, unidos pelo objetivo comum de limitar o poder estatal e assegurar a liberdade humana, ainda que por técnicas distintas ao longo do tempo.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000001-0000-0000-0000-000000000000', 'D', 'A existência de uma Constituição escrita é elemento indispensável para que se reconheça a presença de constitucionalismo, pois somente por meio de um texto formal é possível garantir direitos e estabelecer a separação dos poderes.', 'A Constituição escrita é característica marcante do constitucionalismo moderno, mas não condição indispensável para o reconhecimento de experiências constitucionais em sentido material, como ocorreu no constitucionalismo inglês e em experiências anteriores à modernidade.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000001-0000-0000-0000-000000000000', 'E', 'O constitucionalismo tem como finalidade principal a organização administrativa do Estado, sendo a proteção de direitos fundamentais e a separação dos poderes consequências eventuais, e não elementos centrais do fenômeno constitucional.', 'Desvirtua a essência do constitucionalismo. A limitação do poder, a garantia de direitos fundamentais e a separação dos poderes constituem o núcleo do fenômeno constitucional, conforme expressamente afirmado, inclusive, no art. 16 da Declaração dos Direitos do Homem e do Cidadão de 1789.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000001-0000-0000-0000-000000000000', 1);

-- Q2: Neoconstitucionalismo e seus marcos fundamentais
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000002-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Neoconstitucionalismo'),
  2,
  'multiple_choice',
  'Após as transformações institucionais ocorridas no constitucionalismo do pós-guerra, consolidou-se um novo paradigma jurídico-constitucional, marcado pela centralidade da Constituição, pela normatividade dos princípios e pelo fortalecimento da jurisdição constitucional. A doutrina passou a identificar esse fenômeno como neoconstitucionalismo ou constitucionalismo contemporâneo. Luís Roberto Barroso sistematiza esse movimento a partir da identificação de três marcos fundamentais — histórico, filosófico e teórico — que explicam tanto a origem quanto as principais características desse novo direito constitucional, cujos efeitos se projetam sobre a interpretação constitucional, a atuação do Poder Judiciário e a relação entre Direito, política e moral. Considerando essa sistematização doutrinária e suas repercussões no constitucionalismo brasileiro e europeu, assinale a alternativa correta.',
  'D',
  'O neoconstitucionalismo representa uma mudança estrutural no modo de compreender o Direito Constitucional, resultado direto das experiências históricas traumáticas do século XX. O marco histórico desse movimento está ligado ao constitucionalismo do pós-guerra, com a promulgação de Constituições dotadas de catálogos densos de direitos fundamentais e a criação de tribunais constitucionais voltados à sua proteção, destacando-se a Lei Fundamental de Bonn (1949) e a Constituição Italiana (1947). Posteriormente, processos de redemocratização, como os de Portugal (1976), Espanha (1978) e Brasil (1988), reforçaram essa tendência. No plano filosófico, o neoconstitucionalismo se ancora no pós-positivismo, que surge a partir da superação histórica do jusnaturalismo clássico e do fracasso político do positivismo jurídico. Esse novo paradigma busca ir além da legalidade estrita, sem desprezar o direito posto, promovendo uma reaproximação entre Direito e ética, reconhecendo a normatividade dos princípios e valorizando a argumentação jurídica orientada por uma teoria da justiça, com fundamento na dignidade da pessoa humana. Já o marco teórico traduz as consequências dogmáticas dessa transformação. A Constituição passa a ser reconhecida como norma jurídica dotada de força normativa vinculante, condicionando a validade de todo o ordenamento infraconstitucional. Expande-se a jurisdição constitucional, com tribunais incumbidos da proteção dos direitos fundamentais frente às maiorias políticas, e desenvolve-se uma nova dogmática da interpretação constitucional, marcada pela utilização de princípios, técnicas específicas e métodos próprios. Esses três marcos, em conjunto, explicam a centralidade contemporânea da Constituição, o fenômeno da constitucionalização do Direito e a redefinição do papel dos intérpretes constitucionais no Estado Constitucional de Direito.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000002-0000-0000-0000-000000000000', 'A', 'O marco histórico do neoconstitucionalismo está vinculado exclusivamente à superação do jusnaturalismo clássico, enquanto o marco filosófico decorre da criação dos tribunais constitucionais europeus no pós-guerra.', 'Há inversão conceitual. A superação do jusnaturalismo e do positivismo integra o marco filosófico, e não o histórico. Já a criação de tribunais constitucionais no pós-guerra é elemento típico do marco histórico.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000002-0000-0000-0000-000000000000', 'B', 'O marco filosófico do neoconstitucionalismo corresponde ao retorno do positivismo jurídico estrito, reforçando a centralidade da lei e afastando considerações morais da interpretação constitucional.', 'O neoconstitucionalismo surge justamente como reação ao positivismo jurídico estrito, promovendo sua superação parcial por meio do pós-positivismo, que reconhece a normatividade dos princípios e a dimensão valorativa do Direito.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000002-0000-0000-0000-000000000000', 'C', 'O marco teórico do neoconstitucionalismo limita-se à rigidez constitucional e à supremacia formal da Constituição, não abrangendo mudanças relevantes na teoria da interpretação constitucional.', 'O marco teórico não se limita à rigidez constitucional. Ele envolve transformações profundas na teoria do Direito Constitucional, como a força normativa da Constituição, a expansão da jurisdição constitucional e o desenvolvimento de técnicas específicas de interpretação constitucional.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000002-0000-0000-0000-000000000000', 'D', 'O neoconstitucionalismo estrutura-se a partir de um marco histórico ligado ao constitucionalismo do pós-guerra e aos processos de redemocratização, de um marco filosófico associado ao pós-positivismo e à reaproximação entre Direito e ética, e de um marco teórico caracterizado pela força normativa da Constituição, pela expansão da jurisdição constitucional e por uma nova dogmática interpretativa.', 'A alternativa descreve com precisão os três marcos fundamentais sistematizados por Luís Roberto Barroso, articulando adequadamente seus conteúdos e suas funções explicativas no fenômeno do neoconstitucionalismo.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000002-0000-0000-0000-000000000000', 'E', 'Os marcos do neoconstitucionalismo explicam exclusivamente a experiência brasileira inaugurada com a Constituição de 1988, não sendo aplicáveis ao constitucionalismo europeu do pós-guerra.', 'O neoconstitucionalismo tem raízes no constitucionalismo europeu do pós-guerra, especialmente na Alemanha e na Itália, irradiando-se posteriormente para outros ordenamentos, inclusive o brasileiro.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000002-0000-0000-0000-000000000000', 2);

-- Q3: Constitucionalização do Direito e teses neoconstitucionais
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000003-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Constitucionalização do Direito'),
  3,
  'multiple_choice',
  'Em ação judicial envolvendo a validade de cláusulas contratuais firmadas entre particulares, o magistrado afasta a aplicação literal de dispositivos do Código Civil e fundamenta sua decisão diretamente em princípios constitucionais, especialmente a dignidade da pessoa humana e a proteção dos direitos fundamentais nas relações privadas. Para tanto, utiliza técnica de ponderação, invoca a força normativa da Constituição e sustenta que todo o ordenamento jurídico deve ser interpretado à luz dos valores constitucionais, ainda que isso implique a superação de soluções estritamente formalistas previstas na legislação infraconstitucional. Além disso, o juiz afirma que o Poder Judiciário possui papel relevante na concretização da Constituição, inclusive em matérias tradicionalmente reservadas ao legislador, desde que respeitados os parâmetros da argumentação racional, da proporcionalidade e da fundamentação constitucional adequada. À luz das transformações do constitucionalismo contemporâneo e das teses associadas ao neoconstitucionalismo, assinale a alternativa correta.',
  'B',
  'O caso hipotético ilustra de forma concreta a transição do Estado Legislativo de Direito para o Estado Constitucional de Direito, fenômeno central do neoconstitucionalismo. A decisão judicial parte da premissa de que a Constituição não é apenas um documento político-programático, mas uma norma jurídica dotada de força normativa plena, capaz de irradiar seus valores por todo o ordenamento. A aplicação direta de princípios constitucionais às relações privadas revela a constitucionalização do Direito e a eficácia irradiante dos direitos fundamentais. A utilização da ponderação como técnica decisória demonstra a superação do formalismo e da subsunção mecânica, características do positivismo clássico, sem que isso implique abandono da racionalidade jurídica. Além disso, o protagonismo do Poder Judiciário na concretização constitucional não configura usurpação de funções legislativas, mas exercício legítimo de sua função contramajoritária, desde que pautado por critérios argumentativos, proporcionalidade e respeito à Constituição. O neoconstitucionalismo, portanto, não autoriza arbitrariedade judicial, mas exige decisões mais densamente fundamentadas, capazes de harmonizar princípios, valores e regras à luz da centralidade da Constituição e da dignidade da pessoa humana.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000003-0000-0000-0000-000000000000', 'A', 'A decisão judicial é incompatível com o Estado de Direito, pois a superação da aplicação literal da lei infraconstitucional viola o princípio da legalidade estrita e compromete a separação dos poderes, que exige atuação judicial limitada à subsunção normativa, sendo vedada a aplicação direta de princípios constitucionais em relações privadas.', 'A alternativa constrói uma leitura rígida do princípio da legalidade e da separação dos poderes, típica do Estado Legislativo de Direito. No paradigma neoconstitucional, a legalidade é ressignificada pela constitucionalidade, e a aplicação direta dos princípios constitucionais — inclusive nas relações privadas — é amplamente reconhecida, desde que fundamentada e racional.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000003-0000-0000-0000-000000000000', 'B', 'A atuação do magistrado reflete a constitucionalização do Direito, o reconhecimento da força normativa dos princípios constitucionais, a utilização de métodos abertos de interpretação — como a ponderação — e o protagonismo do Poder Judiciário na concretização da Constituição, características centrais do neoconstitucionalismo.', 'A alternativa descreve com precisão os elementos centrais do neoconstitucionalismo: constitucionalização do Direito, força normativa dos princípios, uso de métodos interpretativos abertos (como a ponderação) e fortalecimento do papel do Judiciário na concretização da Constituição.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000003-0000-0000-0000-000000000000', 'C', 'O caso evidencia uma forma de subjetivismo judicial incompatível com o constitucionalismo contemporâneo, pois a aplicação direta de princípios constitucionais, desacompanhada de critérios estritos de legalidade, transforma o julgador em agente moral, substituindo a vontade do legislador por juízos pessoais de justiça.', 'Embora aparente preocupação legítima com o risco de arbitrariedade judicial, a alternativa incorre em equívoco ao confundir ponderação constitucional com subjetivismo. O neoconstitucionalismo exige argumentação racional, proporcionalidade e controle intersubjetivo das decisões, não decisões baseadas em preferências pessoais do julgador.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000003-0000-0000-0000-000000000000', 'D', 'A fundamentação adotada corresponde ao jusnaturalismo clássico, uma vez que privilegia valores morais abstratos em detrimento do direito positivo, afastando a centralidade da Constituição escrita e relativizando a normatividade das normas jurídicas infraconstitucionais.', 'A alternativa confunde o paradigma pós-positivista com o jusnaturalismo clássico. No caso, os valores aplicados são extraídos da Constituição positiva, dotada de força normativa, e não de uma moral externa ou metafísica desvinculada do ordenamento jurídico.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000003-0000-0000-0000-000000000000', 'E', 'A decisão demonstra adesão ao positivismo jurídico tradicional, na medida em que preserva a supremacia da legislação infraconstitucional e admite a aplicação de princípios apenas como critérios auxiliares de interpretação, sem força normativa autônoma.', 'O positivismo jurídico tradicional justamente nega a normatividade autônoma dos princípios e privilegia a lei infraconstitucional. No caso apresentado, ocorre o oposto: a Constituição assume centralidade e condiciona a interpretação e a aplicação das normas infraconstitucionais.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000003-0000-0000-0000-000000000000', 3);

-- Q4: Substancialismo × Procedimentalismo na Jurisdição Constituci
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000004-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Jurisdição Constitucional'),
  4,
  'multiple_choice',
  'Em determinada ação de controle concentrado de constitucionalidade, o Supremo Tribunal Federal é provocado a se manifestar sobre a validade de uma política pública educacional aprovada pelo Congresso Nacional, que estabelece critérios restritivos para o acesso a determinado benefício estatal. No julgamento, parte dos ministros sustenta que a Constituição de 1988 consagrou valores — como a dignidade da pessoa humana, a igualdade material e a promoção da justiça social — que autorizam o Poder Judiciário a controlar não apenas a regularidade formal do processo legislativo, mas também o conteúdo material das decisões políticas, sempre que estas afrontarem tais valores constitucionais. Outro grupo de ministros, entretanto, defende que o papel da jurisdição constitucional deve ser mais contido, limitando-se a garantir o regular funcionamento do processo democrático, a observância das regras procedimentais e a proteção das condições institucionais da deliberação política, sem substituir as escolhas realizadas pelas maiorias legitimamente eleitas, sobretudo em matérias de elevada controvérsia política, econômica ou moral. À luz das teorias constitucionais acerca do papel da Constituição e da jurisdição constitucional, assinale a alternativa correta.',
  'B',
  'A controvérsia apresentada no caso hipotético expressa, de forma clássica, o embate entre as concepções substancialista e procedimentalista de Constituição e de jurisdição constitucional. Para o substancialismo, a Constituição contém decisões valorativas fundamentais que vinculam não apenas o legislador, mas todo o processo político, legitimando a atuação proativa do Judiciário na correção de escolhas políticas que contrariem tais valores, ainda que formalmente válidas. Nessa perspectiva, a jurisdição constitucional não se limita a verificar a regularidade do procedimento legislativo, mas exerce controle material sobre o conteúdo das políticas públicas, utilizando princípios constitucionais como critérios de validade. O juiz passa a atuar como agente de transformação social, com base na centralidade da Constituição e na força normativa de seus valores. O procedimentalismo, por outro lado, adota postura mais restritiva quanto ao papel do Judiciário. Para essa corrente, a legitimidade democrática das decisões políticas decorre do adequado funcionamento do processo deliberativo, cabendo à jurisdição constitucional apenas assegurar os pressupostos institucionais da democracia, como a liberdade de participação, a igualdade de chances no debate público e o respeito às regras do jogo político. Assim, temas de elevada controvérsia moral, econômica ou social devem ser resolvidos prioritariamente pelas maiorias políticas, e não por juízos substanciais de justiça formulados pelo Judiciário. O conflito entre essas visões está no cerne da judicialização da política e constitui um dos debates mais relevantes do constitucionalismo contemporâneo.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000004-0000-0000-0000-000000000000', 'A', 'A primeira posição descrita corresponde à concepção procedimentalista de Constituição, segundo a qual o Judiciário deve atuar de forma proativa na concretização de valores substantivos, corrigindo decisões políticas que, embora formalmente válidas, contrariem princípios materiais de justiça constitucional.', 'A alternativa inverte os conceitos. A atuação judicial proativa voltada ao controle material das decisões políticas, com base em princípios e valores constitucionais, é característica do substancialismo, e não do procedimentalismo.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000004-0000-0000-0000-000000000000', 'B', 'A divergência apresentada revela o embate entre substancialismo e procedimentalismo, sendo que a posição que admite o controle material das decisões políticas, com fundamento em princípios constitucionais, reflete a concepção substancialista de Constituição, enquanto a postura de autocontenção judicial corresponde à visão procedimentalista.', 'A alternativa identifica corretamente o núcleo da controvérsia: o substancialismo, que admite o controle de resultados das decisões políticas à luz de valores constitucionais, e o procedimentalismo, que defende uma jurisdição constitucional contida, voltada à proteção do processo democrático e das regras do jogo político.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000004-0000-0000-0000-000000000000', 'C', 'Ambas as posições descritas partem de uma concepção substancialista da Constituição, divergindo apenas quanto à intensidade do controle judicial, uma vez que tanto o controle de procedimentos quanto o controle de resultados decorrem da supremacia normativa da Constituição.', 'Embora ambas as correntes reconheçam a supremacia da Constituição, elas divergem profundamente quanto ao papel da jurisdição constitucional. O procedimentalismo rejeita o controle substancial de resultados políticos, restringindo-se ao controle das condições procedimentais da democracia.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000004-0000-0000-0000-000000000000', 'D', 'A posição que defende a limitação da atuação judicial ao controle do processo democrático representa o substancialismo constitucional, pois reconhece que os valores constitucionais devem ser concretizados prioritariamente pelas maiorias políticas, cabendo ao Judiciário apenas a aplicação residual desses valores.', 'A alternativa descreve de forma equivocada o substancialismo. A autocontenção judicial e a deferência às escolhas majoritárias são traços típicos do procedimentalismo, não do substancialismo.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000004-0000-0000-0000-000000000000', 'E', 'O debate apresentado não se relaciona às teorias do substancialismo e do procedimentalismo, mas sim à distinção entre positivismo jurídico e pós-positivismo, sendo irrelevante, nesse contexto, a discussão sobre o papel da jurisdição constitucional no controle de políticas públicas.', 'O debate apresentado é central às teorias do substancialismo e do procedimentalismo, especialmente no que diz respeito à judicialização da política e ao controle jurisdicional de políticas públicas. A alternativa tenta deslocar indevidamente a discussão para outro eixo teórico.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000004-0000-0000-0000-000000000000', 4);

-- Q5: Concepção Política de Constituição (Carl Schmitt)
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000005-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Teoria da Constituição'),
  5,
  'multiple_choice',
  'Durante os trabalhos de uma assembleia constituinte em um Estado recém-saído de um período autoritário, intensos debates surgiram acerca do conteúdo que deveria integrar o texto constitucional. Parte dos constituintes defendia que apenas as normas estruturantes do Estado — como a forma de governo, o regime político, a organização dos poderes e o núcleo essencial dos direitos fundamentais — deveriam ser consideradas verdadeiramente constitucionais. Outras normas, embora relevantes para a administração pública e para a vida social, poderiam constar do texto, mas não teriam o mesmo estatuto político-fundamental. Em meio a essas discussões, um jurista invocou a obra Teoria da Constituição (1928), de Carl Schmitt, para sustentar que a Constituição não se confunde com o conjunto de todas as normas formalmente inseridas no texto constitucional, devendo ser compreendida como expressão de uma decisão política fundamental acerca do modo e da forma de existência da unidade política. Considerando a concepção política de Constituição desenvolvida por Carl Schmitt e sua repercussão na teoria constitucional, assinale a alternativa correta.',
  'C',
  'A concepção política de Constituição, desenvolvida por Carl Schmitt em Teoria da Constituição (1928), parte da distinção essencial entre Constituição e leis constitucionais. Para o autor, a Constituição não se identifica com o conjunto de normas formalmente inseridas no texto constitucional, mas representa a decisão política fundamental sobre o modo e a forma de existência da unidade política. Trata-se de uma decisão concreta e originária, que estrutura o Estado, define seus órgãos fundamentais, estabelece o regime político e fixa os elementos essenciais da ordem estatal. As chamadas leis constitucionais, por sua vez, são normas que integram formalmente o texto constitucional, mas que não possuem relevância político-fundamental. Embora juridicamente válidas e formalmente constitucionais, tais normas não exprimem a decisão política fundante do Estado, razão pela qual não se confundem com a Constituição em sentido próprio. Essa distinção aproxima-se da clássica diferenciação entre Constituição material e Constituição formal. A Constituição material corresponde às normas que efetivamente estruturam o poder político e definem a identidade do Estado, enquanto a Constituição formal abrange todo o conjunto normativo inserido no texto constitucional, independentemente de seu conteúdo político. Importa destacar que a concepção de Schmitt não é sociológica, como a de Lassalle, nem normativa no sentido kelseniano. Seu foco está na decisão política como fundamento da Constituição, o que conduz a uma leitura crítica da ideia de neutralidade constitucional e da equiparação material entre todas as normas constitucionais. Essa perspectiva teve grande impacto na teoria constitucional contemporânea, especialmente nos debates sobre rigidez constitucional, limites materiais de reforma e a própria natureza do poder constituinte.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000005-0000-0000-0000-000000000000', 'A', 'A Constituição, segundo Carl Schmitt, corresponde à soma dos fatores reais de poder que regem a sociedade, refletindo a correlação de forças políticas, econômicas e sociais existentes em determinado momento histórico.', 'A definição apresentada corresponde à concepção sociológica de Constituição, desenvolvida por Ferdinand Lassalle, que compreende a Constituição como a soma dos fatores reais de poder. Carl Schmitt adota uma concepção política, e não sociológica.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000005-0000-0000-0000-000000000000', 'B', 'A distinção entre Constituição e leis constitucionais, formulada por Carl Schmitt, baseia-se exclusivamente no critério formal, segundo o qual apenas normas aprovadas por procedimento agravado podem ser consideradas constitucionais em sentido próprio.', 'A distinção schmittiana não se fundamenta em critérios formais ou procedimentais, mas em critérios materiais e políticos. O que define a Constituição, para Schmitt, não é o procedimento de elaboração da norma, mas seu conteúdo enquanto decisão política fundamental.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000005-0000-0000-0000-000000000000', 'C', 'Para a concepção política de Constituição, a Constituição consiste na decisão política fundamental sobre o modo e a forma de existência da unidade política, ao passo que as leis constitucionais são normas formalmente constitucionais, mas destituídas de relevância político-fundamental.', 'A alternativa expressa fielmente a concepção política de Constituição de Carl Schmitt, ao distinguir a Constituição — como decisão política fundamental sobre a forma e o modo de existência da unidade política — das leis constitucionais, que embora formalmente inseridas no texto constitucional, não possuem esse caráter político-fundamental.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000005-0000-0000-0000-000000000000', 'D', 'Carl Schmitt adota uma concepção sociológica de Constituição, aproximando-se de Ferdinand Lassalle, ao compreender a Constituição como expressão das forças sociais dominantes, sem distinguir Constituição e leis constitucionais.', 'Schmitt não adota uma concepção sociológica de Constituição, nem se aproxima de Lassalle nesse ponto. Ao contrário, sua concepção é política e decisória, distinguindo expressamente Constituição e leis constitucionais.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000005-0000-0000-0000-000000000000', 'E', 'Na concepção política de Constituição, todas as normas inseridas no texto constitucional possuem igual hierarquia material, sendo irrelevante a distinção entre normas estruturalmente fundamentais e normas meramente organizatórias.', 'A concepção política de Constituição rejeita a ideia de igualdade material entre todas as normas constitucionais, justamente porque reconhece que apenas algumas normas traduzem a decisão política fundamental do Estado.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000005-0000-0000-0000-000000000000', 5);

-- Q6: A Constituição como ordem jurídica fundamental, material e a
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000006-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Teoria da Constituição'),
  6,
  'multiple_choice',
  'Hesse) Em determinado país, após a promulgação de uma nova Constituição democrática, surgiram intensos debates políticos e judiciais sobre a extensão da atuação do Poder Judiciário na concretização de normas constitucionais programáticas e principiológicas. Parte da doutrina passou a sustentar que a Constituição deveria ser interpretada de forma estritamente condicionada à realidade política e social existente, sob pena de se transformar em um texto simbólico e ineficaz. Outros autores, porém, defenderam que a Constituição, embora influenciada por fatores históricos, sociais e políticos, não poderia abdicar de sua força normativa, devendo orientar e conformar a atuação estatal e social, ainda que isso exigisse um esforço contínuo de concretização por parte dos poderes públicos e da sociedade. Nesse contexto, um tribunal constitucional, ao julgar a constitucionalidade de uma política pública voltada à promoção de direitos sociais, afirmou que a Constituição não se limita a refletir a realidade fática, mas projeta um dever-ser normativo, cuja eficácia depende da existência de uma vontade coletiva de realizá-la, sem prejuízo da abertura necessária para acomodar diferentes projetos políticos no interior da ordem democrática. Considerando a concepção de Constituição desenvolvida por Konrad Hesse, assinale a alternativa correta.',
  'C',
  'A concepção de Constituição desenvolvida por Konrad Hesse parte da ideia de que a Constituição é a ordem jurídica fundamental de uma comunidade, destinada não apenas à organização do Estado, mas também à conformação da vida social como um todo. Diferentemente das teorias que reduzem a Constituição a um reflexo da realidade política ou a um mero programa político desprovido de força jurídica, Hesse sustenta que a Constituição possui força normativa própria, isto é, capacidade de orientar e vincular a atuação dos poderes públicos e da sociedade. Essa força normativa, contudo, não é automática nem mecânica. Ela depende da existência de uma “vontade de Constituição”, entendida como a disposição coletiva — dos governantes, das instituições e dos cidadãos — de respeitar e concretizar o texto constitucional. Para Hesse, a Constituição não pode renunciar à sua natureza de dever-ser normativo, ainda que deva dialogar com os fatores históricos, sociais e políticos que influenciam sua eficácia. Outro elemento central da teoria hessiana é o caráter aberto da Constituição. O texto constitucional não constitui um sistema fechado e completo, mas um conjunto de princípios fundamentais e elementos estruturantes que deixam margens de conformação ao processo político democrático. Essa abertura permite a coexistência de diferentes concepções políticas e projetos de sociedade, bem como a adaptação da Constituição às mudanças técnicas, econômicas e sociais, sem que isso implique relativização de seus princípios estruturantes. Assim, a Constituição, para Konrad Hesse, é simultaneamente normativa e aberta: normativa porque impõe deveres jurídicos e orienta a atuação estatal; aberta porque admite pluralismo político e evolução histórica, assegurando, com isso, sua própria permanência e eficácia no tempo.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000006-0000-0000-0000-000000000000', 'A', 'A Constituição deve ser compreendida exclusivamente como reflexo das condições históricas, políticas e sociais de uma comunidade, de modo que sua eficácia normativa depende integralmente da correspondência imediata com a realidade fática existente.', 'Afirmar que a Constituição é mero reflexo da realidade corresponde a uma leitura sociologizante extrema, incompatível com a teoria de Konrad Hesse, que insiste na força normativa da Constituição e em seu caráter de dever-ser, ainda que em diálogo com a realidade.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000006-0000-0000-0000-000000000000', 'B', 'A força normativa da Constituição é incompatível com a abertura material do texto constitucional, pois a existência de margens de conformação política compromete a vinculação jurídica dos poderes públicos às normas constitucionais.', 'Para Hesse, a abertura material da Constituição não enfraquece sua força normativa; ao contrário, é condição de sua eficácia em uma sociedade plural e democrática, desde que respeitados os princípios estruturantes da ordem constitucional.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000006-0000-0000-0000-000000000000', 'C', 'A Constituição, enquanto ordem jurídica fundamental, material e aberta, possui força normativa própria, que se realiza por meio da conjugação entre normatividade e realidade, exigindo uma vontade de Constituição e admitindo pluralidade de projetos políticos dentro dos limites constitucionais.', 'A alternativa sintetiza adequadamente a concepção de Constituição como ordem jurídica fundamental, material e aberta, dotada de força normativa, cuja eficácia depende da vontade de Constituição e que admite a convivência de diferentes projetos políticos dentro dos limites constitucionais.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000006-0000-0000-0000-000000000000', 'D', 'A Constituição configura um sistema jurídico fechado e completo, capaz de antecipar todas as situações futuras da vida social, razão pela qual sua eficácia independe de processos interpretativos e de concretização ao longo do tempo.', 'Hesse rejeita a ideia de Constituição como sistema fechado e onicompreensivo. A incompletude e a abertura do texto constitucional são características essenciais de sua teoria, especialmente em sociedades complexas e em constante transformação.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000006-0000-0000-0000-000000000000', 'E', 'A abertura constitucional defendida por Konrad Hesse autoriza a livre conformação do conteúdo constitucional pelos poderes políticos, inclusive com afastamento dos princípios estruturantes e das decisões fundamentais fixadas pelo texto constitucional.', 'A abertura constitucional não autoriza o afastamento dos princípios estruturantes nem das decisões fundamentais da Constituição. A margem de conformação política existe, mas é juridicamente vinculada e limitada pela ordem constitucional.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000006-0000-0000-0000-000000000000', 6);

-- Q7: Elementos constitucionais e funções normativas da Constituiç
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000007-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Teoria da Constituição'),
  7,
  'multiple_choice',
  'Durante o julgamento de uma ação direta de inconstitucionalidade, o Supremo Tribunal Federal foi instado a enfrentar uma controvérsia complexa envolvendo, simultaneamente: (i) a repartição de competências entre os entes federativos; (ii) os limites constitucionais ao poder de tributar; (iii) a legitimidade de políticas públicas voltadas à redução das desigualdades sociais; (iv) a utilização de instrumentos constitucionais de defesa do Estado Democrático de Direito; e (v) a aplicabilidade imediata de normas constitucionais na ausência de legislação infraconstitucional integradora. No voto condutor, o relator destacou que a Constituição Federal não se apresenta como um texto normativamente homogêneo, mas como um sistema estruturado por diferentes espécies de normas constitucionais, cada qual com funções próprias na organização do Estado, na limitação do poder, na promoção de valores sociais, na estabilização institucional e na concretização de seus comandos. À luz da classificação dos elementos constitucionais, assinale a alternativa correta.',
  'C',
  'A Constituição Federal apresenta-se como um sistema normativo complexo, estruturado por diferentes categorias de normas que exercem funções específicas e complementares. A classificação dos elementos constitucionais permite compreender essa diversidade funcional e evita leituras reducionistas do texto constitucional. Os elementos orgânicos organizam o Estado e os Poderes, disciplinando competências e estruturas institucionais. Já os elementos limitativos operam como mecanismos de contenção do poder estatal, por meio da consagração de direitos e garantias fundamentais, expressos ou implicitamente reconhecidos. Os elementos socioideológicos revelam o compromisso constitucional com a justiça social, evidenciando a transição do Estado liberal para o Estado social, ao incorporar normas voltadas à redução das desigualdades e à promoção da dignidade humana. Os elementos de estabilização constitucional desempenham papel crucial na preservação da ordem constitucional, oferecendo instrumentos jurídicos para enfrentar crises institucionais e proteger a Constituição contra rupturas. Por fim, os elementos formais de aplicabilidade disciplinam a eficácia e a incidência das normas constitucionais, reforçando, em muitos casos, sua aplicabilidade direta e imediata, independentemente da atuação do legislador ordinário. Essa arquitetura normativa evidencia que a Constituição não apenas organiza o poder, mas também o limita, legitima, orienta e estabiliza, afirmando-se como centro estruturante de todo o ordenamento jurídico.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000007-0000-0000-0000-000000000000', 'A', 'Os elementos orgânicos da Constituição abrangem exclusivamente o catálogo de direitos e garantias fundamentais, desempenhando a função de limitar o exercício do poder estatal e de assegurar a proteção das liberdades individuais frente à atuação dos Poderes Públicos, razão pela qual se confundem, do ponto de vista funcional, com os elementos limitativos do texto constitucional.', 'Os elementos orgânicos não se confundem com os direitos e garantias fundamentais. Sua função central é estruturar o Estado e os Poderes, disciplinando competências, formas de organização e funcionamento das instituições. A limitação do poder por meio de direitos fundamentais é função típica dos elementos limitativos, e não dos orgânicos.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000007-0000-0000-0000-000000000000', 'B', 'Os elementos socioideológicos da Constituição consistem predominantemente nas normas de organização do Estado e dos Poderes, refletindo uma concepção liberal clássica de neutralidade estatal diante das desigualdades econômicas e sociais, razão pela qual não possuem função normativa voltada à implementação de políticas públicas ou à promoção da justiça social.', 'Os elementos socioideológicos expressam justamente o caráter compromissório da Constituição, refletindo a superação do Estado liberal clássico e a incorporação de valores sociais, econômicos e distributivos. Incluem normas de direitos sociais e da ordem econômica e social, voltadas à promoção da justiça social e à redução das desigualdades.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000007-0000-0000-0000-000000000000', 'C', 'Os elementos de estabilização constitucional compreendem normas destinadas à defesa da Constituição, do Estado e das instituições democráticas, incluindo mecanismos como o controle de constitucionalidade, a intervenção federal e estadual, o processo de emenda constitucional e os regimes constitucionais de exceção.', 'Os elementos de estabilização constitucional são voltados à preservação da própria ordem constitucional e das instituições democráticas, abrangendo mecanismos de controle de constitucionalidade, intervenção federativa, processo de emenda constitucional e regimes excepcionais previstos no texto constitucional.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000007-0000-0000-0000-000000000000', 'D', 'Os elementos formais de aplicabilidade têm como principal finalidade condicionar a eficácia das normas constitucionais à edição de legislação infraconstitucional, restringindo a incidência direta da Constituição e preservando a primazia do legislador ordinário na concretização dos direitos fundamentais.', 'Os elementos formais de aplicabilidade não têm por objetivo restringir a eficácia das normas constitucionais. Ao contrário, em diversos casos reforçam sua incidência direta e imediata, como ocorre com o art. 5º, §1º, da Constituição Federal, que afirma a aplicabilidade imediata dos direitos fundamentais.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000007-0000-0000-0000-000000000000', 'E', 'Os elementos limitativos da Constituição restringem-se aos direitos individuais clássicos expressamente previstos no art. 5º da Constituição Federal, não abrangendo direitos fundamentais implícitos ou limitações materiais ao poder estatal reconhecidas pela jurisprudência constitucional.', 'Os elementos limitativos não se restringem aos direitos individuais clássicos expressos no art. 5º. A jurisprudência do STF reconhece direitos fundamentais atípicos e limitações implícitas ao poder estatal, como as limitações constitucionais ao poder de tributar, que também exercem função limitadora.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000007-0000-0000-0000-000000000000', 7);

-- Q8: Justiça de Transição, Constituição e Direitos Fundamentais (
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000008-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Justiça de Transição'),
  8,
  'multiple_choice',
  'ajustada) Após a promulgação da Constituição Federal de 1988, o Brasil iniciou um processo gradual de enfrentamento das violações sistemáticas de direitos humanos ocorridas durante o regime civil-militar instaurado em 1964. Esse processo envolveu medidas de reparação econômica, iniciativas voltadas ao direito à memória e à verdade, reformas institucionais e intensos debates sobre a responsabilização jurídica de agentes estatais envolvidos em graves violações de direitos humanos. Nesse contexto, uma associação de familiares de mortos e desaparecidos políticos ajuizou ação judicial buscando: (i) o reconhecimento do dever estatal de investigar os fatos ocorridos durante o regime autoritário; (ii) a responsabilização civil dos agentes envolvidos; e (iii) o afastamento da interpretação da Lei nº 6.683/1979 (Lei da Anistia) como obstáculo absoluto à persecução de graves violações de direitos humanos, invocando, para tanto, a Constituição de 1988, o art. 8º do ADCT, a jurisprudência da Corte Interamericana de Direitos Humanos e precedentes recentes dos tribunais superiores brasileiros. Considerando a teoria da Justiça de Transição, a ordem constitucional brasileira e o diálogo entre o direito interno e o direito internacional dos direitos humanos, assinale a alternativa correta.',
  'C',
  'A Justiça de Transição constitui um conjunto articulado de mecanismos jurídicos, políticos e institucionais destinados a enfrentar o legado de graves violações de direitos humanos praticadas em contextos de regimes autoritários ou conflitos armados, com vistas à consolidação do Estado Democrático de Direito. Não se trata de uma justiça excepcional ou meramente retrospectiva, mas de um modelo normativo orientado para o futuro, cuja finalidade central é impedir a repetição das práticas violadoras, restaurar a dignidade das vítimas e fortalecer as instituições democráticas. No plano teórico e normativo, a Justiça de Transição está intimamente vinculada aos direitos fundamentais, especialmente aos direitos à dignidade humana, à verdade, à memória, à justiça e à reparação. A sua lógica rompe com a ideia de que a superação de períodos autoritários pode ser alcançada por meio do esquecimento institucional ou da neutralização jurídica do passado. Ao contrário, parte-se do pressuposto de que não há democracia constitucional sólida sem enfrentamento crítico das violações pretéritas, sob pena de perpetuação de práticas autoritárias e de normalização da impunidade. No contexto latino-americano, a Justiça de Transição ganha relevo em razão da sucessão de regimes autoritários vivenciados ao longo das décadas de 1960, 1970 e 1980. A experiência regional demonstrou que processos de redemocratização marcados exclusivamente por pactos políticos de silêncio tendem a produzir democracias frágeis, com déficits estruturais de legitimidade e de proteção efetiva aos direitos humanos. É nesse cenário que se desenvolve a jurisprudência da Corte Interamericana de Direitos Humanos, afirmando, de forma reiterada, que leis de autoanistia são incompatíveis com a Convenção Americana de Direitos Humanos quando impedem a investigação, o julgamento e a punição de graves violações, como tortura, execuções extrajudiciais e desaparecimentos forçados. No Brasil, a Justiça de Transição assumiu contornos próprios e tardios. Embora a Lei nº 6.683/1979 (Lei da Anistia) represente um marco inicial do processo de transição, ela se insere em um contexto político ainda autoritário e operou uma anistia bilateral, alcançando tanto vítimas quanto agentes da repressão. Esse modelo gerou um obstáculo significativo à persecução penal dos crimes de Estado, tensionando, ao longo das décadas seguintes, a relação entre memória, justiça e reconciliação. A Constituição Federal de 1988, contudo, inaugura um novo paradigma. Ao consagrar a dignidade da pessoa humana como fundamento da República (art. 1º, III), ao constitucionalizar um amplo catálogo de direitos fundamentais e ao prever, no art. 8º do ADCT, medidas específicas de reparação às vítimas de perseguição política, a Constituição demonstra abertura normativa à Justiça de Transição. Ainda que não tenha enfrentado diretamente a responsabilização penal dos agentes do regime, a CF/88 rompe com a lógica do esquecimento e legitima políticas públicas de memória, verdade e reparação. A partir dos anos 2000, especialmente após 2007, observa-se um avanço significativo na agenda transicional brasileira. Destacam-se a criação da Comissão Especial sobre Mortos e Desaparecidos Políticos, da Comissão de Anistia, a publicação do relatório Direito à Memória e à Verdade, a promulgação da Lei de Acesso à Informação e, posteriormente, a instituição da Comissão Nacional da Verdade. Esses instrumentos revelam que a Justiça de Transição não se esgota no plano judicial, operando também por meio de mecanismos administrativos, simbólicos e políticos, todos dotados de relevância constitucional. No plano jurisdicional, a temática assume complexidade adicional. Em 2010, o Supremo Tribunal Federal, ao julgar a ADPF nº 153, declarou válida a interpretação da Lei de Anistia que beneficiou agentes da repressão, adotando uma leitura fundada na transição negociada e na segurança jurídica. Contudo, essa decisão passou a conviver com a condenação internacional do Brasil no caso Gomes Lund e outros vs. Brasil (Guerrilha do Araguaia), no qual a Corte Interamericana afirmou que a Lei de Anistia brasileira não pode servir de obstáculo ao dever estatal de investigar, julgar e punir graves violações de direitos humanos. Esse cenário revela uma tensão estrutural entre o direito constitucional interno e o direito internacional dos direitos humanos, resolvida, progressivamente, por meio do diálogo das cortes e da incorporação de parâmetros internacionais na interpretação constitucional. A Súmula nº 647 do STJ, ao reconhecer a imprescritibilidade das ações indenizatórias decorrentes de perseguição política, representa um avanço relevante nesse processo, reforçando a centralidade da dignidade da pessoa humana e a natureza continuada das violações praticadas pelo Estado autoritário. Por fim, a Justiça de Transição não deve ser compreendida como um mecanismo de revanche ou de instabilidade institucional. Trata-se, ao contrário, de uma condição mínima para a '
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000008-0000-0000-0000-000000000000', 'A', 'A Justiça de Transição, no contexto brasileiro, deve ser compreendida exclusivamente como um mecanismo político de reconciliação nacional, cujo núcleo normativo se exaure na concessão da anistia ampla, geral e irrestrita prevista na Lei nº 6.683/1979, bem como em medidas indenizatórias de caráter patrimonial, sendo incompatível com a Constituição de 1988 qualquer forma de reinterpretação judicial do período autoritário, sob pena de violação à segurança jurídica, à estabilidade institucional e ao pacto político que viabilizou a redemocratização do Estado brasileiro.', 'Apesar de dialogar com o argumento da segurança jurídica e do pacto político da redemocratização, a alternativa reduz a Justiça de Transição a anistia e indenização econômica, ignorando seus pilares estruturantes e desconsiderando a evolução constitucional e internacional dos direitos humanos, bem como o dever estatal de investigar graves violações.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000008-0000-0000-0000-000000000000', 'B', 'A Justiça de Transição consiste essencialmente em um modelo de responsabilização penal retroativa, destinado à persecução criminal dos agentes públicos envolvidos em violações de direitos humanos, razão pela qual instrumentos não jurisdicionais — como comissões da verdade, políticas públicas de memória, programas administrativos de reparação ou iniciativas simbólicas de reconhecimento estatal — carecem de legitimidade jurídica e não se inserem adequadamente no conceito de justiça transicional adotado no direito constitucional contemporâneo.', 'A Justiça de Transição não se limita à persecução penal. Trata-se de um modelo plural e complexo, que combina mecanismos judiciais e não judiciais, conforme parâmetros da ONU e da Corte Interamericana, sendo incorreta a exclusão de instrumentos como comissões da verdade e políticas de memória.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000008-0000-0000-0000-000000000000', 'C', 'A Justiça de Transição compreende um conjunto de instrumentos voltados à justiça, à verdade, à memória, à reparação e às garantias de não repetição, podendo envolver mecanismos judiciais e não judiciais, sendo incompatível com a Constituição e com a Convenção Americana de Direitos Humanos a utilização de leis de autoanistia como obstáculo absoluto à investigação e à responsabilização por graves violações de direitos humanos.', 'A alternativa expressa, de forma equilibrada, a concepção contemporânea de Justiça de Transição, reconhecendo sua natureza multifacetada e a incompatibilidade de leis de autoanistia com as obrigações internacionais de direitos humanos, especialmente no que concerne a graves violações.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000008-0000-0000-0000-000000000000', 'D', 'A Constituição de 1988 adotou um modelo predominantemente conciliatório de superação do passado autoritário, priorizando a pacificação institucional e a estabilização do sistema político, de modo que iniciativas posteriores voltadas à reconstrução da memória histórica, à responsabilização civil do Estado ou à revisão crítica da Lei de Anistia extrapolariam os limites do texto constitucional, configurando ingerência indevida do Poder Judiciário em escolhas políticas consolidadas no processo de transição democrática.', 'A Constituição de 1988 não consagrou um modelo de esquecimento institucional. Ao contrário, o art. 8º do ADCT e a centralidade da dignidade da pessoa humana demonstram abertura constitucional à memória, à verdade e à reparação, legitimando a atuação estatal e judicial nesse campo.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000008-0000-0000-0000-000000000000', 'E', 'A Justiça de Transição, embora relevante sob o ponto de vista histórico, sociológico e político, não possui densidade normativa suficiente para produzir efeitos jurídicos vinculantes no ordenamento brasileiro, razão pela qual suas diretrizes não podem ser utilizadas como parâmetro hermenêutico na interpretação da Constituição nem para influenciar a atuação do Poder Judiciário em demandas relativas a fatos ocorridos durante o regime autoritário.', 'A Justiça de Transição possui densidade normativa relevante, influenciando a interpretação constitucional e a atuação jurisdicional, como demonstram a jurisprudência da Corte IDH, a criação da Comissão Nacional da Verdade e a Súmula nº 647 do STJ.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000008-0000-0000-0000-000000000000', 8);

-- Q9: Estado de Coisas Inconstitucional (ECI)
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000009-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Estado de Coisas Inconstitucional'),
  9,
  'multiple_choice',
  'Em determinado país, estudos oficiais, relatórios de órgãos de controle e decisões judiciais reiteradas passaram a apontar a existência de um quadro persistente de violação de direitos fundamentais em um setor específico de políticas públicas. As violações são amplas, contínuas e afetam um grupo vulnerável de forma estrutural, não se limitando a casos isolados. Apesar de sucessivas recomendações e de iniciativas pontuais, as autoridades públicas responsáveis demonstram incapacidade reiterada de modificar o cenário, seja por inércia institucional, seja por falhas estruturais profundas na formulação e execução das políticas públicas. Diante desse contexto, é ajuizada Arguição de Descumprimento de Preceito Fundamental (ADPF) perante o Supremo Tribunal Federal, com o objetivo de obter o reconhecimento de um Estado de Coisas Inconstitucional e a adoção de medidas estruturais mínimas voltadas à superação das violações. No curso do processo, diversas entidades da sociedade civil são admitidas como amicus curiae e passam a apresentar manifestações, defendendo a ampliação das providências inicialmente requeridas, em razão de agravamento superveniente da situação fática. O relator, sensível à gravidade do quadro, avalia a possibilidade de determinar providências adicionais não expressamente formuladas no pedido inicial. Considerando a teoria do Estado de Coisas Inconstitucional, a experiência brasileira a partir da ADPF nº 347/DF e o entendimento jurisprudencial do Supremo Tribunal Federal, assinale a alternativa correta.',
  'C',
  'O Estado de Coisas Inconstitucional constitui uma técnica decisória excepcional, desenvolvida originalmente pela Corte Constitucional colombiana e incorporada ao debate constitucional brasileiro a partir da ADPF nº 347/DF. Seu pressuposto central é a constatação de um quadro estrutural de violação generalizada e persistente de direitos fundamentais, associado à incapacidade reiterada das autoridades públicas de modificar a realidade por meio de respostas institucionais ordinárias. No caso brasileiro, o STF reconheceu que o sistema penitenciário vivenciava um Estado de Coisas Inconstitucional, marcado por falhas estruturais e pela ineficácia de políticas públicas fragmentadas. Ao fazê-lo, a Corte deixou claro que não lhe competia substituir o Legislativo ou o Executivo na formulação de políticas públicas, mas sim atuar como indutor institucional, impondo deveres mínimos de atuação e cobrando a coordenação entre os órgãos responsáveis. Importante destacar que, embora o controle abstrato de constitucionalidade admita causa de pedir aberta, o pedido permanece delimitado pelos termos da inicial, não sendo possível ao relator ampliar de ofício o objeto da ação. Do mesmo modo, os amici curiae desempenham papel relevante na qualificação do debate constitucional, mas não detêm legitimidade para formular pedidos cautelares ou incidentais. Assim, o Estado de Coisas Inconstitucional revela uma forma de tutela estrutural dos direitos fundamentais que busca equilibrar efetividade constitucional e respeito à separação de poderes, atuando como mecanismo excepcional de superação de omissões estatais graves e persistentes, sem romper com as balizas processuais e institucionais do controle de constitucionalidade.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000009-0000-0000-0000-000000000000', 'A', 'O reconhecimento do Estado de Coisas Inconstitucional autoriza o Supremo Tribunal Federal a assumir papel substitutivo dos Poderes Legislativo e Executivo, permitindo-lhe definir diretamente o conteúdo e a forma das políticas públicas necessárias à superação das violações estruturais, independentemente dos limites do pedido formulado na ação de controle concentrado.', 'A alternativa A está incorreta porque atribui ao Supremo Tribunal Federal um papel substitutivo dos demais Poderes, o que não se coaduna com a jurisprudência da Corte. No reconhecimento do Estado de Coisas Inconstitucional, o STF tem afirmado que não lhe compete definir o conteúdo específico das políticas públicas, mas apenas impor medidas estruturais mínimas e cobrar a atuação coordenada dos órgãos competentes, respeitando a separação de poderes.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000009-0000-0000-0000-000000000000', 'B', 'A técnica do Estado de Coisas Inconstitucional admite a ampliação do objeto da ADPF pelo relator, em razão da abertura da causa de pedir no controle abstrato de constitucionalidade, bem como reconhece legitimidade processual aos amici curiae para requerer medidas cautelares autônomas sempre que houver agravamento relevante da situação fática.', 'A alternativa B está incorreta ao sustentar que a abertura da causa de pedir no controle abstrato autorizaria a ampliação do pedido pelo relator e conferiria legitimidade processual ativa aos amici curiae. O STF já assentou que, embora a causa de pedir seja aberta, o pedido é delimitado, e os amici curiae não possuem legitimidade para formular pedidos cautelares ou ampliar o objeto da ação.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000009-0000-0000-0000-000000000000', 'C', 'O Estado de Coisas Inconstitucional caracteriza-se pela constatação de falhas estruturais e violações generalizadas de direitos fundamentais, legitimando a atuação judicial para impor medidas estruturais mínimas; todavia, essa atuação deve respeitar os limites do pedido formulado e as regras de legitimidade processual, não sendo possível ao relator ampliar de ofício o objeto da ação.', 'A alternativa C está correta, pois sintetiza adequadamente os pressupostos do Estado de Coisas Inconstitucional e os limites da atuação judicial. Reconhece-se a possibilidade de imposição de medidas estruturais mínimas diante de falhas sistêmicas, mas preservam- se os limites do pedido e as regras de legitimidade próprias do controle concentrado, em consonância com o entendimento firmado pelo STF na ADPF nº 347/DF.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000009-0000-0000-0000-000000000000', 'D', 'O reconhecimento do Estado de Coisas Inconstitucional pressupõe violação reiterada de direitos fundamentais e autoriza a imposição judicial de obrigações de fazer ao Poder Público; contudo, uma vez admitidos no processo, os amici curiae passam a compartilhar legitimidade ativa com os legitimados constitucionais para formular pedidos incidentais no curso da ação.', 'A alternativa D está incorreta ao atribuir legitimidade ativa aos amici curiae para a formulação de pedidos incidentais. A jurisprudência do STF é firme no sentido de que o amicus curiae atua como colaborador do debate constitucional, não como parte processual com poderes de iniciativa.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000009-0000-0000-0000-000000000000', 'E', 'A técnica do Estado de Coisas Inconstitucional, embora não prevista expressamente no texto constitucional, pode ser manejada em hipóteses excepcionais de violação estrutural de direitos fundamentais, permitindo ao Poder Judiciário atuar como indutor institucional de políticas públicas, inclusive afastando as limitações decorrentes do princípio da separação de poderes e da reserva do possível.', 'A alternativa E está incorreta porque sugere que o reconhecimento do Estado de Coisas Inconstitucional afastaria limites estruturais como a separação de poderes e a reserva do possível. O STF, ao contrário, tem afirmado que a atuação judicial nesse contexto deve ser excepcional e cuidadosamente delimitada, não implicando substituição dos demais Poderes.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000009-0000-0000-0000-000000000000', 9);

-- Q10: Competência no Controle Abstrato e Normas de Reprodução Obri
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000010-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Controle de Constitucionalidade'),
  10,
  'multiple_choice',
  'Competência no Controle Abstrato e Normas de Reprodução Obrigatória O Governador de determinado Estado da Federação ajuíza ação direta de inconstitucionalidade perante o Tribunal de Justiça local contra lei municipal que disciplina aspectos do processo legislativo do Município, alegando violação a dispositivos da Constituição Estadual. Os dispositivos invocados, contudo, reproduzem quase integralmente regras constantes da Constituição Federal relacionadas à separação de poderes e ao devido processo legislativo. O Tribunal de Justiça julga procedente a ação, declarando a inconstitucionalidade da lei municipal. Inconformado, o Município interpõe recurso extraordinário ao Supremo Tribunal Federal, sustentando, entre outros pontos, a incompetência do Tribunal de Justiça para exercer controle abstrato de constitucionalidade com base em normas da Constituição Federal, ainda que reproduzidas no texto da Constituição Estadual. Considerando a sistemática do controle de constitucionalidade no ordenamento jurídico brasileiro, a distinção entre normas de reprodução obrigatória e normas de imitação, bem como o entendimento consolidado do Supremo Tribunal Federal, assinale a alternativa correta.',
  'C',
  'No sistema brasileiro de controle de constitucionalidade, a definição da competência para o julgamento das ações diretas depende fundamentalmente do parâmetro de controle utilizado. O Supremo Tribunal Federal é competente para julgar ações diretas de inconstitucionalidade de leis ou atos normativos federais, estaduais ou distritais em face da Constituição Federal. Já os Tribunais de Justiça exercem o controle abstrato de constitucionalidade de leis estaduais ou municipais em face da Constituição Estadual ou da Lei Orgânica do Distrito Federal. A complexidade surge quando a Constituição Estadual reproduz normas da Constituição Federal. Nesses casos, é necessário distinguir entre normas de reprodução obrigatória e normas de imitação. As normas de reprodução obrigatória — também chamadas de normas centrais ou de observância obrigatória — são aquelas que, por força da própria Constituição Federal, devem integrar o texto constitucional dos Estados, ainda que não haja repetição expressa. Trata-se de construção jurisprudencial consolidada pelo STF. O Supremo Tribunal Federal, ao julgar o Tema 484 da repercussão geral, firmou entendimento no sentido de que os Tribunais de Justiça podem exercer controle abstrato de constitucionalidade de leis municipais (e também estaduais) utilizando como parâmetro normas da Constituição Federal, desde que essas normas sejam de reprodução obrigatória e tenham sido incorporadas à Constituição Estadual. Nessas hipóteses, é cabível recurso extraordinário ao STF, cuja decisão, por decorrer de processo objetivo, produzirá efeitos erga omnes. Assim, o modelo brasileiro combina descentralização do controle abstrato com a preservação da supremacia da Constituição Federal, permitindo que os Tribunais de Justiça atuem como garantidores da ordem constitucional local, sem afastar o papel uniformizador do Supremo Tribunal Federal.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000010-0000-0000-0000-000000000000', 'A', 'O Tribunal de Justiça não possui competência para exercer controle abstrato de constitucionalidade de lei municipal quando o parâmetro utilizado reproduz normas da Constituição Federal, pois o controle concentrado de normas municipais em face da Constituição Federal é de competência exclusiva do Supremo Tribunal Federal.', 'A alternativa A está incorreta porque desconsidera a possibilidade reconhecida pelo Supremo Tribunal Federal de os Tribunais de Justiça exercerem controle abstrato de constitucionalidade de leis municipais com base em normas da Constituição Federal que sejam de reprodução obrigatória, desde que incorporadas ao texto da Constituição Estadual.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000010-0000-0000-0000-000000000000', 'B', 'O controle abstrato de constitucionalidade de lei municipal somente pode ser exercido pelo Tribunal de Justiça quando o parâmetro invocado for norma da Constituição Estadual dotada de autonomia normativa plena, sendo vedada a utilização de normas que correspondam, ainda que parcialmente, a dispositivos da Constituição Federal.', 'A alternativa B está incorreta ao exigir que o parâmetro possua autonomia normativa plena e desvinculada da Constituição Federal. A jurisprudência do STF admite expressamente o uso de normas estaduais que reproduzem dispositivos federais de observância obrigatória como parâmetro válido para o controle abstrato exercido pelos Tribunais de Justiça.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000010-0000-0000-0000-000000000000', 'C', 'O Tribunal de Justiça pode exercer controle abstrato de constitucionalidade de leis municipais utilizando como parâmetro normas da Constituição Federal reproduzidas na Constituição Estadual, desde que se trate de normas de reprodução obrigatória, sendo cabível recurso extraordinário ao STF contra a decisão proferida.', 'A alternativa C está correta, pois reflete com precisão o entendimento firmado pelo STF no Tema 484 da repercussão geral. Os Tribunais de Justiça podem exercer controle abstrato de constitucionalidade de leis municipais (ou estaduais) utilizando como parâmetro normas da Constituição Federal, desde que se trate de normas de reprodução obrigatória, sendo cabível recurso extraordinário ao STF, cuja decisão terá eficácia erga omnes.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000010-0000-0000-0000-000000000000', 'D', 'A utilização de normas da Constituição Estadual que reproduzem dispositivos da Constituição Federal como parâmetro de controle abstrato configura hipótese de usurpação da competência do Supremo Tribunal Federal, razão pela qual a decisão do Tribunal de Justiça deve ser considerada nula, independentemente da natureza da norma reproduzida.', 'A alternativa D está incorreta porque não há usurpação de competência quando o Tribunal de Justiça exerce controle abstrato com base em normas de reprodução obrigatória. Ao contrário, trata-se de competência reconhecida e delimitada pela própria jurisprudência do Supremo Tribunal Federal.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000010-0000-0000-0000-000000000000', 'E', 'O controle abstrato de constitucionalidade de lei municipal fundado em normas de reprodução obrigatória deve ser realizado diretamente pelo Supremo Tribunal Federal, cabendo aos Tribunais de Justiça apenas o controle concreto incidental dessas normas, sem possibilidade de controle concentrado.', 'A alternativa E está incorreta ao restringir o controle abstrato das normas de reprodução obrigatória ao Supremo Tribunal Federal. O modelo brasileiro admite a atuação dos Tribunais de Justiça no controle concentrado, desde que o parâmetro seja norma de reprodução obrigatória incorporada à Constituição Estadual.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000010-0000-0000-0000-000000000000', 10);

-- Q11: Administração Pública em Sentido Objetivo e Subjetivo — Fome
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000011-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Administração Pública'),
  11,
  'multiple_choice',
  'Administração Pública em Sentido Objetivo e Subjetivo — Fomento, Polícia Administrativa, Serviço Público e Intervenção O Município de Santa Aurora, visando “organizar o espaço urbano e estimular a economia local”, aprovou um pacote de medidas administrativas. • Primeiro, editou lei municipal que proíbe a abertura de novos minimercados e farmácias em um raio de 500 metros de qualquer estabelecimento do mesmo ramo, sob o argumento de evitar “concentração comercial” e “proteger o comércio tradicional”. • Em seguida, por decreto do Prefeito, fixou horário máximo para atendimento ao público de todas as agências bancárias do Município, justificando a necessidade de “reduzir filas e melhorar o fluxo de trânsito”. • Paralelamente, a Prefeitura lançou um programa de estímulo fiscal e subvenções para startups que se instalassem na cidade e mantivessem, por dois anos, um número mínimo de empregos formais. • Por fim, determinou que a empresa municipal de saneamento, por contrato de concessão, ampliasse a rede de água e esgoto em bairros periféricos, sob pena de multa e caducidade, e criou uma “força-tarefa” para fiscalizar o cumprimento de padrões sanitários em feiras livres, com poder de interdição. A Associação Comercial local ajuíza ação judicial alegando: (i) confusão conceitual do Município sobre o que é Administração Pública em sentido objetivo e subjetivo; (ii) excesso na atuação municipal ao regular bancos; e (iii) inconstitucionalidade da lei que restringe a instalação de estabelecimentos do mesmo ramo. Com base nos conceitos de Administração Pública em sentido objetivo (material/funcional) e sentido subjetivo (orgânico/formal), bem como nas categorias fomento, polícia administrativa, serviço público e intervenção, e considerando a orientação sumulada do STF/STJ, assinale a alternativa correta.',
  'D',
  'Em provas de Administração Pública, é comum o candidato confundir quem atua (sentido subjetivo) com o que é feito (sentido objetivo). No caso, o Município, a empresa municipal e seus agentes são a face subjetiva. Mas o núcleo da questão está no conteúdo funcional das medidas: incentivar a iniciativa privada por benefícios é fomento; fiscalizar e limitar atividades em nome da saúde pública é polícia administrativa; assegurar saneamento, ainda que por delegação contratual, é serviço público; e “intervenção” é categoria própria, que não se confunde com política de incentivo. Quando o enunciado adiciona súmulas, ele também testa se o aluno sabe “acoplar” a teoria ao controle de constitucionalidade e de competência: Município tem espaço para disciplinar horário de funcionamento de comércio (SV 38), mas isso não significa carta branca para tratar horário bancário como se fosse mero comércio local (STJ 19). Do mesmo modo, ainda que o Município invoque urbanismo e “ordenação do espaço”, uma lei que impede a instalação de estabelecimentos do mesmo ramo em determinada área tende a colidir com a livre concorrência (SV 49). Assim, a alternativa correta é a que classifica adequadamente as funções administrativas e, ao mesmo tempo, reconhece os limites materiais e competenciais do poder normativo municipal.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000011-0000-0000-0000-000000000000', 'A', 'As medidas 1 e 2 constituem típicas hipóteses de serviço público municipal, porque tratam do ordenamento do comércio e da organização do atendimento bancário, e, por serem atividades voltadas ao bem-estar coletivo, inserem-se na prestação direta de utilidades públicas; além disso, como o Município atua no interesse local, pode limitar livremente o funcionamento de agências bancárias e impedir a instalação de estabelecimentos concorrentes sem que haja ofensa à livre concorrência.', 'Ela reclassifica indevidamente medidas típicas de polícia administrativa e de competência normativa como se fossem serviço público. Além disso, trata como livremente disponível ao Município a disciplina de horário bancário e, simultaneamente, valida restrição territorial que impede concorrentes do mesmo ramo, ignorando que esse tipo de vedação é visto como violador da livre concorrência quando impede a instalação de estabelecimentos do mesmo ramo em área delimitada (SV 49).', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000011-0000-0000-0000-000000000000', 'B', 'O pacote municipal descreve apenas Administração Pública em sentido subjetivo, pois o foco está na atuação do Prefeito, da empresa municipal e de seus agentes, sendo irrelevante classificar as atividades em fomento, polícia, serviço público ou intervenção; por consequência, qualquer controle judicial deve se limitar à verificação formal da competência do órgão emissor dos atos, já que, sendo matéria administrativa, a avaliação de conteúdo econômico e concorrencial seria discricionária e imune à sindicabilidade.', 'Apesar de a Administração em sentido subjetivo de fato envolver Prefeito, empresa municipal e agentes, isso não elimina a necessidade (cobrada em prova) de classificar a atuação em fomento, polícia, serviço público e intervenção, que são categorias do sentido objetivo. A alternativa ainda cria uma barreira artificial de “controle apenas formal”, quando a compatibilidade material com a Constituição (como livre concorrência e competência) é tema típico de controle judicial.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000011-0000-0000-0000-000000000000', 'C', 'O item 3 (subvenções e estímulos fiscais) caracteriza intervenção direta do Estado no domínio econômico, porque o Município interfere na livre iniciativa ao escolher setores beneficiados; já o item 4 caracteriza fomento, pois a ampliação de saneamento e a imposição de metas à concessionária consistem em incentivo indireto à melhoria do serviço, e não em prestação de serviço público; por fim, a lei municipal do item 1 é válida por expressar o poder local de ordenar o uso do solo urbano e proteger o comércio tradicional, mesmo que restrinja a concorrência.', 'Ela troca os conceitos: chama de “intervenção direta” aquilo que é classicamente fomento (subvenções/estímulos), e chama de “fomento” aquilo que é serviço público (saneamento por concessão), além de afirmar a validade da lei municipal que impede instalação de estabelecimentos do mesmo ramo em certa área, justamente onde há forte objeção constitucional ligada à livre concorrência.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000011-0000-0000-0000-000000000000', 'D', 'O item 3 corresponde a fomento; a fiscalização com possibilidade de interdição no item 4 corresponde a polícia administrativa; a ampliação do saneamento por concessão no item 4 situa-se em serviço público; e a lei do item 1 tende a afrontar a livre concorrência quando impede a instalação de estabelecimentos do mesmo ramo em determinada área, enquanto a fixação do horário bancário (item 2) não se insere na competência municipal quando confrontada com a orientação sumulada pertinente.', 'A alternativa enquadra corretamente: (i) estímulos/subvenções como fomento; (ii) fiscalização com poder de interdição como polícia administrativa; (iii) saneamento delegado como serviço público; e (iv) aponta os limites constitucionais/sumulares relevantes: a restrição de “mesmo ramo” tende a violar livre concorrência (SV 49) e a disciplina de horário bancário encontra óbice no entendimento sumulado correspondente (STJ 19), distinguindo-se do simples horário de funcionamento de estabelecimento comercial (SV 38).', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000011-0000-0000-0000-000000000000', 'E', 'O item 2 é exemplo de polícia administrativa municipal plenamente legítima, pois o Município pode disciplinar o atendimento bancário para proteger o consumidor e o trânsito local; o item 1 é exemplo de intervenção estatal adequada, uma vez que políticas de “desconcentração” são compatíveis com a Constituição; o item 3 não configura fomento, mas prestação indireta de serviço público de emprego; e o item 4 não é serviço público, e sim mera atividade econômica estatal, razão pela qual não caberia concessão nem fiscalização com sanções.', 'Ela tenta “encaixar” tudo em categorias inadequadas: transforma horário bancário em polícia administrativa municipal plena (ignorando a delimitação sumulada), trata a vedação concorrencial como intervenção legítima sem enfrentar o problema de livre concorrência, e rebatiza fomento e serviço público com conceitos artificiais (“serviço público de emprego”, “mera atividade econômica estatal”), contrariando a dogmática administrativa clássica.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000011-0000-0000-0000-000000000000', 11);

-- Q12: Princípio da Publicidade e suas Exceções
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000012-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Princípios da Administração Pública'),
  12,
  'multiple_choice',
  'Princípio da Publicidade e suas Exceções Em determinado Estado da Federação, uma agência reguladora instaurou processo administrativo sancionador contra concessionária de serviço público de energia elétrica, em razão de supostas falhas graves na prestação do serviço. Durante a tramitação do processo, a agência decidiu decretar sigilo integral dos autos, sob o argumento de que a divulgação das informações poderia gerar instabilidade econômica e insegurança social, além de afetar a imagem institucional da concessionária. Uma associação civil de defesa dos consumidores impetrou mandado de segurança coletivo, sustentando violação ao princípio da publicidade, previsto no art. 37 da Constituição Federal, bem como ao direito fundamental de acesso à informação (art. 5º, XIV e XXXIII). Alegou ainda que o sigilo generalizado compromete a transparência e o controle social da atividade regulatória. Considerando o regime constitucional do princípio da publicidade, suas limitações expressas no art. 5º da Constituição Federal e o entendimento do Supremo Tribunal Federal acerca da matéria, assinale a alternativa correta.',
  'C',
  '(texto corrido – aprofundada) O princípio da publicidade integra o rol dos princípios expressos no art. 37, caput, da Constituição Federal, constituindo elemento essencial do Estado Democrático de Direito. Sua função vai além da mera divulgação formal de atos administrativos: ele viabiliza o controle social, assegura transparência, fortalece a legitimidade das decisões públicas e concretiza o direito fundamental à informação. No plano dos direitos fundamentais, o art. 5º, XIV, assegura o acesso à informação, resguardado o sigilo da fonte quando necessário ao exercício profissional. O art. 5º, XXXIII, estabelece o direito de todos receberem informações dos órgãos públicos, ressalvadas aquelas cujo sigilo seja imprescindível à segurança da sociedade e do Estado. Já o art. 5º, LX, admite restrição à publicidade de atos processuais quando a defesa da intimidade ou o interesse social o exigirem. Desse modo, o princípio da publicidade não possui caráter absoluto. Todavia, suas restrições são excepcionais, exigem fundamento constitucional ou legal específico e devem ser interpretadas restritivamente. O sigilo não pode ser decretado com base em justificativas genéricas, sob pena de violação ao núcleo essencial do direito à informação e de comprometimento da transparência administrativa. No âmbito dos processos administrativos sancionadores instaurados por agências reguladoras, o STF tem afirmado que a publicidade constitui regra durante toda a tramitação, admitindo-se restrições pontuais quando enquadradas nas hipóteses constitucionais de sigilo. A proteção da imagem institucional ou o receio de repercussões econômicas não se confundem, por si, com segurança da sociedade ou do Estado. Assim, a disciplina constitucional da publicidade revela uma lógica estruturante: a transparência é a regra; o sigilo é a exceção, submetido a fundamentação qualificada, proporcionalidade e controle jurisdicional.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000012-0000-0000-0000-000000000000', 'A', 'A decretação de sigilo integral em processo administrativo sancionador é compatível com a Constituição sempre que a Administração Pública considerar que a publicidade pode causar abalo econômico ou institucional, por se tratar de juízo discricionário da autoridade administrativa.', 'Transforma a exceção em regra e amplia indevidamente a margem discricionária da Administração Pública. A Constituição Federal estabelece hipóteses específicas e taxativas de restrição à publicidade, relacionadas à segurança da sociedade e do Estado, à proteção da intimidade ou a situações expressamente previstas em lei. A mera alegação de abalo econômico ou institucional não autoriza, por si só, a decretação de sigilo integral.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000012-0000-0000-0000-000000000000', 'B', 'O princípio da publicidade possui caráter absoluto no âmbito dos processos administrativos sancionadores, razão pela qual não se admitem restrições, ainda que haja fundamento constitucional relacionado à segurança da sociedade ou do Estado.', 'Atribui caráter absoluto ao princípio da publicidade, o que não corresponde ao modelo constitucional brasileiro. O art. 5º, XXXIII e LX, da Constituição admite expressamente hipóteses de restrição, desde que justificadas e proporcionais, especialmente quando o sigilo seja imprescindível à segurança da sociedade e do Estado ou quando a defesa da intimidade ou o interesse social o exigirem.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000012-0000-0000-0000-000000000000', 'C', 'A publicidade constitui regra geral aplicável aos processos administrativos sancionadores, sendo possível a restrição pontual e fundamentada apenas quando presentes hipóteses constitucionais ou legais específicas, não sendo legítimo o sigilo integral baseado em justificativa genérica.', 'O princípio da publicidade constitui regra estruturante da Administração Pública (art. 37, caput, CF) e é reforçado pelo direito fundamental de acesso à informação (art. 5º, XIV e XXXIII). A jurisprudência do STF reconhece que processos administrativos sancionadores devem observar a publicidade como regra, admitindo-se restrições apenas em hipóteses específicas, devidamente fundamentadas, não sendo legítimo o sigilo integral com base em justificativas genéricas ou abstratas.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000012-0000-0000-0000-000000000000', 'D', 'O sigilo pode ser decretado em processos administrativos sempre que houver interesse da Administração Pública na preservação da imagem institucional ou na proteção de sua política regulatória, ainda que não haja previsão constitucional expressa.', 'Amplia indevidamente as hipóteses de sigilo, conferindo à Administração poder para restringir a publicidade com base em interesse institucional amplo e indeterminado. O modelo constitucional exige fundamento jurídico específico e controle de proporcionalidade.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000012-0000-0000-0000-000000000000', 'E', 'A restrição à publicidade em processos administrativos sancionadores depende exclusivamente de previsão na lei infraconstitucional, não sendo admissível fundamentação direta na Constituição Federal para limitar o acesso às informações.', 'A própria Constituição prevê hipóteses diretas de restrição à publicidade. A limitação pode decorrer tanto de previsão legal quanto de fundamento constitucional expresso, desde que observados os critérios de necessidade e proporcionalidade.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000012-0000-0000-0000-000000000000', 12);

-- Q13: Poder de Polícia e Delegação a Pessoas Jurídicas de Direito 
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000013-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Poder de Polícia'),
  13,
  'multiple_choice',
  'Poder de Polícia e Delegação a Pessoas Jurídicas de Direito Privado (RE 633782 – STF) O Estado Alfa editou lei delegando a uma sociedade de economia mista estadual, cujo capital social é majoritariamente público e que presta exclusivamente serviço público em regime não concorrencial, o exercício de determinadas atividades de fiscalização e aplicação de sanções administrativas relacionadas à regulação de transporte intermunicipal. Uma associação de empresas do setor ajuizou ação judicial sustentando que a delegação seria inconstitucional, pois o poder de polícia é atividade típica de Estado e não poderia ser exercido por pessoa jurídica de direito privado, ainda que integrante da Administração Pública indireta. Considerando a evolução jurisprudencial do Supremo Tribunal Federal, especialmente o entendimento fixado no RE 633782 (Tema de Repercussão Geral), assinale a alternativa correta.',
  'B',
  'O poder de polícia consiste na atividade administrativa de restringir ou condicionar o exercício de direitos individuais em benefício do interesse público. Tradicionalmente, era compreendido como função típica e indelegável do Estado, especialmente em razão de seus atributos de coercibilidade, autoexecutoriedade e imperatividade. Durante longo período, prevaleceu no STF o entendimento de que o poder de polícia não poderia ser delegado a pessoas jurídicas de direito privado. O STJ, por sua vez, admitia delegação parcial — chamada de “bloco de polícia” — apenas quanto aos atos de consentimento e fiscalização, mantendo como indelegáveis os atos sancionatórios. O julgamento do RE 633782 representou inflexão relevante na jurisprudência. O STF fixou tese segundo a qual é constitucional a delegação do poder de polícia a pessoas jurídicas de direito privado integrantes da Administração Pública indireta, desde que atendidos requisitos cumulativos: (i) capital social majoritariamente público; (ii) prestação exclusiva de serviço público próprio do Estado; (iii) atuação em regime não concorrencial; (iv) delegação formalizada por lei. A Corte fundamentou sua decisão na natureza jurídica híbrida das empresas estatais prestadoras de serviço público, reconhecendo nelas “feições autárquicas” quando exercem atividades típicas de Estado. Nessas hipóteses, não há incompatibilidade estrutural entre o exercício do poder de polícia e o regime jurídico da entidade. Foram afastados os principais argumentos contrários à delegação: • não há exigência de autorização constitucional expressa; • a estabilidade não é requisito absoluto para o exercício do poder de polícia; • a coercibilidade pode ser exercida por estatais com regime próximo ao da Fazenda Pública; • a finalidade lucrativa não constitui elemento definidor quando a entidade presta serviço público próprio do Estado. Importante ressalva: permanece indelegável a chamada “ordem de polícia”, isto é, a função normativa (legislativa), que envolve a criação de restrições abstratas por meio de lei. O que se admite delegar são os atos administrativos de consentimento, fiscalização e aplicação de sanções, dentro dos limites legais. Portanto, o modelo atual adotado pelo STF equilibra a supremacia do interesse público com a organização administrativa descentralizada, permitindo que determinadas estatais exerçam funções típicas de Estado, desde que respeitados os parâmetros fixados na tese de repercussão geral.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000013-0000-0000-0000-000000000000', 'A', 'O poder de polícia é atividade típica e exclusiva de Estado, sendo absolutamente indelegável a qualquer pessoa jurídica de direito privado, ainda que integrante da Administração Pública indireta e prestadora de serviço público.', 'Reproduz entendimento jurisprudencial anterior à consolidação da tese fixada no RE 633782. O Supremo Tribunal Federal superou a compreensão de indelegabilidade absoluta, admitindo a delegação do poder de polícia a determinadas pessoas jurídicas de direito privado integrantes da Administração Pública indireta, desde que preenchidos requisitos específicos.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000013-0000-0000-0000-000000000000', 'B', 'É constitucional a delegação, por meio de lei, do exercício do poder de polícia a pessoas jurídicas de direito privado integrantes da Administração Pública indireta, desde que possuam capital social majoritariamente público, prestem exclusivamente serviço público próprio do Estado e atuem em regime não concorrencial.', 'Reflete exatamente a tese de repercussão geral firmada pelo STF: é constitucional a delegação do poder de polícia, por meio de lei, a pessoas jurídicas de direito privado integrantes da Administração Pública indireta, com capital social majoritariamente público, que prestem exclusivamente serviço público de atuação própria do Estado e em regime não concorrencial.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000013-0000-0000-0000-000000000000', 'C', 'A delegação do poder de polícia é possível apenas quanto aos atos de consentimento e fiscalização, permanecendo vedada a delegação da aplicação de sanções administrativas, independentemente da natureza da entidade delegatária.', 'Restringe indevidamente o alcance da decisão do STF. Embora o STJ tenha adotado, em momento anterior, a chamada teoria do “bloco de polícia”, admitindo delegação apenas dos atos de consentimento e fiscalização a particulares não integrantes da Administração, o STF passou a admitir, nas hipóteses delineadas na tese, inclusive a aplicação de sanções, ressalvada a fase legislativa (ordem de polícia), que permanece indelegável.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000013-0000-0000-0000-000000000000', 'D', 'A delegação do poder de polícia às sociedades de economia mista é admitida desde que estas explorem atividade econômica em regime concorrencial, pois nesse caso atuam sob regime jurídico integralmente privado.', 'Associa a possibilidade de delegação ao regime concorrencial de exploração econômica, quando a tese fixada pelo STF exige justamente o contrário: que a entidade atue em regime não concorrencial e preste serviço público próprio do Estado, afastando a lógica de atuação orientada ao lucro.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000013-0000-0000-0000-000000000000', 'E', 'O exercício do poder de polícia por sociedade de economia mista exige autorização constitucional expressa, sendo insuficiente a previsão em lei ordinária estadual para legitimar a delegação.', 'O STF afastou o argumento da necessidade de autorização constitucional expressa. A delegação pode ocorrer por meio de lei, sendo compatível com o regime jurídico híbrido das estatais prestadoras de serviço público.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000013-0000-0000-0000-000000000000', 13);

-- Q14: Teoria da Dupla Garantia (Responsabilidade Civil do Estado)
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000014-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Responsabilidade Civil do Estado'),
  14,
  'multiple_choice',
  'Teoria da Dupla Garantia (Responsabilidade Civil do Estado) Durante uma operação de fiscalização, um agente público estadual, no exercício de suas funções, causa danos materiais a um particular ao agir de forma negligente. A vítima propõe ação indenizatória diretamente contra o agente público, alegando que ele foi o responsável imediato pelo dano. Com base no art. 37, § 6º da Constituição Federal e na tese fixada pelo Supremo Tribunal Federal no RE 1027633 (Tema de Repercussão Geral), assinale a alternativa correta.',
  'B',
  'A chamada teoria da dupla garantia decorre da interpretação do art. 37, § 6º da Constituição Federal, que consagra a responsabilidade civil objetiva do Estado pelos danos causados por seus agentes, nessa qualidade. Essa norma constitucional cumpre duas funções protetivas simultâneas: Primeira garantia – proteção da vítima: A vítima não precisa comprovar dolo ou culpa do agente público, bastando demonstrar a conduta administrativa, o dano e o nexo causal. A responsabilidade do Estado é objetiva, fundada na teoria do risco administrativo. Segunda garantia – proteção do agente público: O agente não pode ser demandado diretamente pela vítima pelos danos decorrentes do exercício da função pública. Sua responsabilidade é subjetiva e somente poderá ser apurada em ação regressiva promovida pelo ente público, caso demonstrados dolo ou culpa. No julgamento do RE 1027633, o STF fixou tese no sentido de que a ação indenizatória deve ser ajuizada contra o Estado ou pessoa jurídica prestadora de serviço público, sendo parte ilegítima para a ação o autor do ato. Ao ente público é assegurado o direito de regresso contra o agente responsável, nos casos de dolo ou culpa. Portanto, o modelo constitucional brasileiro busca equilibrar a proteção do administrado e a segurança jurídica do agente público, impedindo a responsabilização direta deste perante a vítima, mas preservando a possibilidade de ressarcimento ao erário quando comprovada atuação culposa ou dolosa.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000014-0000-0000-0000-000000000000', 'A', 'A vítima pode optar por ajuizar a ação indenizatória tanto contra o agente público quanto contra o Estado, formando litisconsórcio facultativo, pois ambos respondem solidariamente pelo dano causado.', 'A teoria da dupla garantia não admite a formação de litisconsórcio facultativo entre Estado e agente público. O Supremo Tribunal Federal firmou entendimento de que a vítima deve demandar diretamente o ente estatal ou a pessoa jurídica prestadora de serviço público, sendo o agente parte ilegítima para compor o polo passivo da ação indenizatória.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000014-0000-0000-0000-000000000000', 'B', 'A ação indenizatória deve ser proposta contra o Estado ou a pessoa jurídica prestadora de serviço público, sendo o agente público parte ilegítima para figurar no polo passivo, assegurado ao ente público o direito de regresso em caso de dolo ou culpa.', 'Traduz fielmente a tese fixada no RE 1027633. O art. 37, § 6º da Constituição estabelece responsabilidade objetiva do Estado pelos danos causados por seus agentes nessa qualidade. A vítima deve ajuizar a ação contra o ente público, que posteriormente poderá exercer o direito de regresso contra o agente, caso haja comprovação de dolo ou culpa.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000014-0000-0000-0000-000000000000', 'C', 'O agente público responde objetivamente perante a vítima sempre que atuar no exercício da função, independentemente de culpa, podendo o Estado ser chamado ao processo apenas como responsável subsidiário.', 'A responsabilidade objetiva recai sobre o Estado, e não sobre o agente público. A responsabilização direta do agente perante a vítima não encontra amparo na teoria da dupla garantia, conforme interpretação consolidada pelo STF.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000014-0000-0000-0000-000000000000', 'D', 'A responsabilidade civil do Estado afasta completamente qualquer possibilidade de responsabilização posterior do agente público, ainda que comprovado dolo ou culpa grave.', 'O direito de regresso é expressamente previsto na Constituição. O ente público pode ajuizar ação regressiva contra o agente responsável quando houver dolo ou culpa, de modo que não há imunidade absoluta do agente.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000014-0000-0000-0000-000000000000', 'E', 'A vítima deve comprovar dolo ou culpa do agente público para ajuizar ação diretamente contra ele, sendo desnecessária a participação do Estado no processo.', 'Contraria frontalmente a tese de repercussão geral. Ainda que se alegue culpa do agente, a ação deve ser proposta contra o Estado, sendo o agente parte ilegítima para figurar diretamente na demanda indenizatória proposta pela vítima.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000014-0000-0000-0000-000000000000', 14);

-- Q15: Procedimento de Justificação na Contratação Direta (Lei 14.1
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000015-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Licitações e Contratos'),
  15,
  'multiple_choice',
  'Procedimento de Justificação na Contratação Direta (Lei 14.133/21) O Secretário de determinado Município decide realizar contratação direta, sob alegação de hipótese de dispensa de licitação, para aquisição de equipamentos hospitalares. O processo administrativo é instaurado sem parecer jurídico, sem justificativa de preço e sem demonstração da compatibilidade orçamentária. Ainda assim, a contratação é autorizada e executada. Posteriormente, o Tribunal de Contas identifica que não estavam presentes os requisitos legais da contratação direta e que houve erro grosseiro na condução do procedimento. Com base nos arts. 72 e 73 da Lei nº 14.133/21, assinale a alternativa correta.',
  'B',
  '(texto corrido – aprofundada) A Lei nº 14.133/21 estabelece que a contratação direta — que compreende as hipóteses de dispensa e inexigibilidade — não dispensa a formalização de um procedimento administrativo estruturado. O art. 72 determina que o processo seja instruído com documentos essenciais, dentre eles: • Documento de formalização da demanda; • Estimativa de despesa; • Parecer jurídico; • Demonstração de disponibilidade orçamentária; • Comprovação de habilitação do contratado; • Razão da escolha do contratado; • Justificativa de preço; • Autorização da autoridade competente. A justificativa de preço e a razão da escolha do contratado são elementos centrais para evitar favorecimentos indevidos e assegurar a economicidade e a impessoalidade. Além disso, o ato autorizador da contratação direta deve ser divulgado em sítio eletrônico oficial, em observância aos princípios da publicidade e da transparência. Quanto à responsabilidade, o art. 73 estabelece que, caso a contratação direta indevida ocorra com dolo, fraude ou erro grosseiro, o agente público e o contratado responderão solidariamente pelo dano ao erário, sem prejuízo de outras sanções. Portanto, a contratação direta é exceção à regra da licitação, mas não é espaço de informalidade: exige motivação, transparência e rigor procedimental.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000015-0000-0000-0000-000000000000', 'A', 'A ausência de parecer jurídico e de justificativa de preço não compromete a validade da contratação direta, desde que haja urgência administrativa e posterior ratificação pela autoridade competente.', 'A Lei 14.133/21 estabelece de forma expressa os documentos que devem instruir o processo de contratação direta, incluindo parecer jurídico e justificativa de preço. A urgência administrativa não afasta a necessidade de observância do procedimento formal exigido pelo art. 72.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000015-0000-0000-0000-000000000000', 'B', 'O processo de contratação direta exige instrução formal com documentos específicos previstos em lei, sendo obrigatória a justificativa de preço e a razão da escolha do contratado, sob pena de irregularidade.', 'Reproduz o comando do art. 72 da Lei 14.133/21. O procedimento de contratação direta deve ser devidamente instruído com documentos formais, incluindo justificativa de preço, razão da escolha do contratado, estimativa de despesa, parecer jurídico, comprovação de habilitação e autorização da autoridade competente. A ausência desses elementos compromete a regularidade da contratação.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000015-0000-0000-0000-000000000000', 'C', 'A contratação direta indevida gera responsabilidade exclusiva do agente público responsável, não alcançando o contratado, ainda que comprovado dolo ou erro grosseiro.', 'O art. 73 da Lei 14.133/21 prevê responsabilidade solidária do contratado e do agente público quando a contratação direta indevida ocorrer com dolo, fraude ou erro grosseiro.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000015-0000-0000-0000-000000000000', 'D', 'A divulgação do ato de autorização da contratação direta é facultativa, podendo a Administração manter o procedimento sob sigilo administrativo até o encerramento do contrato.', 'O ato que autoriza a contratação direta ou o extrato do contrato deve ser divulgado e mantido à disposição do público em sítio eletrônico oficial, garantindo transparência e controle social.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000015-0000-0000-0000-000000000000', 'E', 'A responsabilidade solidária entre contratado e agente público somente ocorre quando houver comprovação de fraude, não se aplicando aos casos de dolo ou erro grosseiro.', 'A responsabilidade solidária prevista no art. 73 abrange hipóteses de dolo, fraude ou erro grosseiro, não estando restrita exclusivamente à fraude.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000015-0000-0000-0000-000000000000', 15);

-- Q16: Justiça Restaurativa e Sistemas Não Judiciais de Composição 
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000016-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Justiça Restaurativa'),
  16,
  'multiple_choice',
  'Justiça Restaurativa e Sistemas Não Judiciais de Composição de Litígios Em determinado município, foi implantado um programa de Justiça Restaurativa no âmbito do Juizado Especial Criminal, com a realização de círculos restaurativos em casos de infrações penais de menor potencial ofensivo. O projeto prevê a participação da vítima, do ofensor e de membros da comunidade, com o objetivo de promover responsabilização, reparação do dano e prevenção da reincidência. Um grupo de operadores do Direito questiona a legitimidade dessa prática, alegando que ela comprometeria a função punitiva do Estado e representaria renúncia ao monopólio estatal da jurisdição penal. À luz da formação humanística, assinale a alternativa correta.',
  'B',
  'A justiça restaurativa surge como resposta crítica ao modelo tradicional punitivista, especialmente diante da constatação empírica de que o encarceramento massivo não tem sido eficaz na prevenção da reincidência. Sob perspectiva humanística: • o conflito penal é visto como ruptura de relações sociais; • a vítima deixa de ser mero instrumento probatório; • o ofensor é chamado à responsabilização ativa; • a comunidade participa da reconstrução do tecido social. Esse modelo dialoga com: • a política anticarcerária; • a vitimologia; • o art. 5º, XLVI, da Constituição (pluralidade de sanções); • o art. 98, I, da Constituição (Juizados Especiais); • a tendência internacional incentivada por organismos como ONU e CNJ. Não se trata de abolir o Direito Penal, mas de pensar em algo melhor do que o Direito Penal puramente encarcerador — uma releitura que busca eficiência, humanidade e redução da reincidência sem abdicar da institucionalidade estatal.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000016-0000-0000-0000-000000000000', 'A', 'A justiça restaurativa representa modelo incompatível com o sistema constitucional brasileiro, pois o Estado, ao assumir o monopólio da jurisdição penal, afastou definitivamente qualquer forma de protagonismo da vítima na resolução do conflito criminal, devendo a sanção penal manter caráter exclusivamente retributivo e aflitivo.', 'Parte da premissa de que o monopólio estatal da jurisdição penal exclui qualquer forma de participação ativa da vítima. O modelo constitucional não impede a valorização da vítima nem a adoção de mecanismos restaurativos, desde que inseridos no âmbito institucional e sob supervisão estatal. A função punitiva do Estado não se reduz à retribuição, podendo abranger prevenção, reparação e reintegração social.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000016-0000-0000-0000-000000000000', 'B', 'A justiça restaurativa insere-se em uma política anticarcerária e dialoga com o modelo constitucional brasileiro ao valorizar a participação da vítima, a responsabilização ativa do ofensor e a busca por soluções consensuais, sem afastar o papel do Estado, mas redefinindo a forma de gestão do conflito penal.', 'Reconhece que a justiça restaurativa integra uma política anticarcerária voltada à redução da reincidência e à humanização da resposta penal, sem abdicar do papel estatal. Trata-se de uma redefinição da forma de enfrentamento do conflito, com maior protagonismo das partes e da comunidade, mas sob a égide do ordenamento jurídico.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000016-0000-0000-0000-000000000000', 'C', 'A justiça restaurativa substitui integralmente o processo penal tradicional, transferindo às partes a responsabilidade pela definição da resposta estatal ao crime, inclusive nos delitos graves, com prevalência da autonomia privada sobre a função pública da persecução penal.', 'A justiça restaurativa não substitui integralmente o processo penal tradicional nem se aplica indistintamente a delitos graves. Além disso, não transfere às partes a titularidade da persecução penal, que continua sendo pública, mas introduz mecanismos consensuais dentro de limites normativos.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000016-0000-0000-0000-000000000000', 'D', 'A lógica restaurativa rompe com o modelo estatal de solução de conflitos ao permitir que a vítima retome o papel central típico do período pré-estatal, no qual a resposta ao crime dependia exclusivamente de sua vontade e iniciativa.', 'Confunde justiça restaurativa com retorno ao modelo de vingança privada. A justiça restaurativa opera dentro da institucionalidade estatal, sob coordenação do Poder Judiciário ou de políticas públicas reconhecidas, não havendo retomada do modelo pré- estatal de autotutela.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000016-0000-0000-0000-000000000000', 'E', 'A adoção da justiça restaurativa implica relativização do princípio da legalidade penal e enfraquecimento da função preventiva da pena, na medida em que a sanção deixa de cumprir papel simbólico de reafirmação da autoridade do Estado.', 'A justiça restaurativa não elimina o princípio da legalidade nem impede a função preventiva da pena. Ao contrário, busca resultados concretos de responsabilização e prevenção da reincidência, muitas vezes com maior eficácia social do que a prisão.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000016-0000-0000-0000-000000000000', 16);

-- Q17: Fases das Políticas Públicas e Judicialização da Política
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000017-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Políticas Públicas'),
  17,
  'multiple_choice',
  'Fases das Políticas Públicas e Judicialização da Política Após ampla mobilização nas redes sociais envolvendo um caso isolado de violência em escola pública, um juiz de primeiro grau, em decisão liminar proferida em ação civil pública, determinou que o Estado implementasse imediatamente um programa estadual obrigatório de monitoramento eletrônico em todas as escolas, com instalação de detectores de metal, contratação emergencial de seguranças privados e criação de protocolo unificado de revista pessoal de estudantes. A decisão foi fundamentada na proteção da dignidade da pessoa humana, no direito à segurança e na prioridade absoluta da criança e do adolescente. Especialistas em políticas públicas passaram a sustentar que a medida judicial poderia representar exemplo problemático de judicialização da política e de supressão das etapas próprias de formulação de políticas públicas. À luz da teoria dos ciclos das políticas públicas e do ativismo judicial, assinale a alternativa correta.',
  'B',
  'A teoria dos ciclos das políticas públicas parte da premissa de que a construção de uma política pública envolve processo complexo e democrático, que inclui: • identificação social do problema; • internalização política do tema; • formulação técnica de alternativas; • deliberação institucional; • execução; • avaliação. A judicialização da política torna-se problemática quando: • decisões são tomadas com base em casos isolados; • há fundamentação exclusivamente principiológica; • inexistem estudos técnicos prévios; • não há análise de impacto orçamentário; • suprime-se a etapa de avaliação democrática. A crítica ao ativismo judicial não significa negar a importância do Judiciário na proteção de direitos fundamentais, mas aponta o risco institucional de substituição da racionalidade política por decisões casuísticas e imediatistas. Esse é o núcleo problemático que a alternativa correta evidencia.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000017-0000-0000-0000-000000000000', 'A', 'A decisão judicial é plenamente adequada sob a perspectiva constitucional, pois a invocação de princípios estruturantes, como dignidade da pessoa humana e prioridade absoluta da criança, autoriza o Judiciário a substituir integralmente a atuação administrativa e legislativa sempre que houver risco potencial a direitos fundamentais, sendo irrelevante, nesse contexto, a observância das fases técnicas de formulação, deliberação e avaliação típicas do ciclo das políticas públicas.', 'Embora direitos fundamentais possam justificar intervenção judicial, não se pode afirmar que a observância das fases das políticas públicas seja irrelevante. A crítica à judicialização está justamente na supressão dessas etapas, que possuem função democrática e técnica. A decisão judicial não pode automaticamente substituir a racionalidade político-administrativa.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000017-0000-0000-0000-000000000000', 'B', 'A crítica à decisão decorre da constatação de que o Judiciário, ao determinar a implementação imediata de política pública estrutural, pode ter suprimido etapas essenciais do ciclo das políticas públicas, como a percepção social consolidada do problema, a inclusão formal na agenda governamental, a formulação plural de alternativas, a análise de viabilidade orçamentária e a avaliação posterior de resultados, comprometendo a racionalidade democrática do processo decisório.', 'Identifica adequadamente o problema institucional envolvido: a possível supressão de fases do ciclo das políticas públicas, especialmente a formulação técnica, a análise de viabilidade e a avaliação posterior, o que compromete a construção democrática e participativa da política pública.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000017-0000-0000-0000-000000000000', 'C', 'Não há qualquer problema institucional na decisão, pois a comoção social amplamente divulgada pela mídia e pelas redes digitais configura, por si só, etapa suficiente de agenda setting, tornando dispensável a formulação técnica e o debate parlamentar, especialmente quando a medida judicial busca assegurar proteção preventiva a grupos vulneráveis.', 'Comoção social e repercussão midiática não equivalem automaticamente à etapa formal de agenda setting. A agenda pública exige institucionalização política e debate estruturado, não sendo suficiente a mobilização episódica para legitimar a implementação imediata de políticas estruturais por decisão judicial.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000017-0000-0000-0000-000000000000', 'D', 'A decisão é ilegítima exclusivamente porque políticas públicas jamais podem ser objeto de controle judicial, uma vez que a separação dos poderes impede qualquer forma de interferência do Judiciário em matéria administrativa, ainda que estejam em jogo direitos fundamentais de elevada densidade normativa.', 'A separação dos poderes não impede controle judicial de políticas públicas. O Judiciário pode atuar para assegurar direitos fundamentais, especialmente diante de omissões inconstitucionais. O problema não é a possibilidade de controle, mas a forma e o grau da intervenção.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000017-0000-0000-0000-000000000000', 'E', 'A crítica ao ativismo judicial, no caso apresentado, limita-se ao fato de que o magistrado não aguardou o trânsito em julgado da decisão antes de determinar a implementação da política pública, sendo que, caso a decisão fosse definitiva, não haveria qualquer questionamento teórico acerca da intervenção judicial.', 'A crítica não se relaciona com o momento processual da decisão (liminar ou definitiva), mas com a supressão das etapas estruturais do ciclo das políticas públicas. Mesmo decisão transitada em julgado poderia ser objeto de crítica sob essa perspectiva teórica.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000017-0000-0000-0000-000000000000', 17);

-- Q18: Transformação Digital no Poder Judiciário e Garantias Fundam
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000018-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Processo Digital e Garantias Fundamentais'),
  18,
  'multiple_choice',
  'Transformação Digital no Poder Judiciário e Garantias Fundamentais Durante a pandemia da COVID-19, um Tribunal de Justiça estadual instituiu, por meio de ato administrativo, a obrigatoriedade de tramitação exclusivamente digital de todos os processos judiciais, inclusive daqueles que envolvem partes sem representação por advogado. Além disso, determinou que todas as audiências fossem realizadas exclusivamente por videoconferência, vedando-se a realização presencial, salvo autorização excepcional da Presidência do Tribunal. Em determinado caso, uma parte hipossuficiente, residente em zona rural sem acesso estável à internet, alegou violação ao acesso à justiça (art. 5º, XXXV, CF/88) e ao devido processo legal, sustentando que a transformação digital não poderia comprometer direitos fundamentais. À luz da transformação digital no Poder Judiciário, da Lei nº 11.419/2006, das Resoluções do CNJ e dos princípios constitucionais, assinale a alternativa correta.',
  'B',
  '(texto corrido – aprofundada) A transformação digital do Judiciário representa avanço estrutural importante: • maior celeridade; • padronização de sistemas (PJe); • economia de recursos; • ampliação de transparência. Entretanto, sob perspectiva humanística e constitucional, surgem desafios: 1. Exclusão digital: nem todos possuem acesso à internet ou domínio tecnológico. 2. Assimetria estrutural: partes hipossuficientes podem ser prejudicadas. 3. Risco de automatização decisória: a produtividade não pode suprimir análise individualizada. 4. Eficiência versus garantia: a tecnologia é meio, não fim. A Constituição de 1988 ampliou direitos. A digitalização deve servir à concretização desses direitos, não à sua restrição.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000018-0000-0000-0000-000000000000', 'A', 'A transformação digital do Poder Judiciário, especialmente após a Lei nº 11.419/2006, autoriza a substituição integral e definitiva do processo físico pelo eletrônico, independentemente de políticas de inclusão digital ou de medidas compensatórias, pois o avanço tecnológico constitui imperativo institucional que prevalece sobre eventuais dificuldades individuais das partes.', 'Embora a informatização esteja prevista em lei, ela não pode prevalecer sobre direitos fundamentais. A eficiência administrativa não pode justificar a restrição concreta ao acesso à justiça. A ausência de inclusão digital pode gerar desigualdade estrutural e violação ao princípio da isonomia processual.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000018-0000-0000-0000-000000000000', 'B', 'A informatização do processo judicial, embora prevista na Lei nº 11.419/2006 e regulamentada pelo CNJ nos termos do art. 196 do CPC/2015, deve observar as normas fundamentais do processo, de modo que a transformação digital não pode se converter em obstáculo ao acesso à justiça, exigindo do Judiciário mecanismos de inclusão e adaptação para partes vulneráveis.', 'Reconhece a constitucionalidade da transformação digital, mas condiciona sua implementação à observância das normas fundamentais do processo. A digitalização deve ampliar — e não restringir — o acesso à jurisdição.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000018-0000-0000-0000-000000000000', 'C', 'A competência do CNJ para regulamentar o PJe implica autonomia absoluta dos tribunais para instituírem modelos exclusivamente digitais de tramitação processual, sem necessidade de observância ao princípio da inafastabilidade da jurisdição, pois a digitalização é etapa natural da modernização administrativa.', 'A competência regulamentar do CNJ não é absoluta. Ela deve respeitar a Constituição e o CPC. O princípio da inafastabilidade da jurisdição impede que barreiras tecnológicas inviabilizem o acesso ao Judiciário.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000018-0000-0000-0000-000000000000', 'D', 'A obrigatoriedade de audiências exclusivamente virtuais é constitucional em qualquer hipótese, pois o uso de tecnologia da informação, especialmente após a pandemia, passou a integrar o núcleo essencial do devido processo legal contemporâneo.', 'O uso de tecnologia não integra, por si só, o núcleo essencial do devido processo legal. Audiências virtuais são instrumentos legítimos, mas não podem ser impostas de modo a gerar prejuízo concreto às partes.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000018-0000-0000-0000-000000000000', 'E', 'A validade dos atos processuais eletrônicos depende exclusivamente da utilização de certificado digital nos moldes da ICP-Brasil, sendo irrelevante a análise de eventual prejuízo material decorrente da impossibilidade prática de acesso ao sistema eletrônico por parte de litigantes hipossuficientes.', 'A validade formal da assinatura digital não esgota a análise constitucional. O processo exige também exame de efetividade e ausência de prejuízo. A exclusão digital pode comprometer direitos processuais.', false);
INSERT INTO simulado_questions (simulado_id, question_id, position)
VALUES ('00000000-0000-0000-0000-000000000001', '00000018-0000-0000-0000-000000000000', 18);

-- Q19: Direitos Humanos — Fundamentos Teóricos
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000019-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Fundamentos Teóricos dos Direitos Humanos'),
  19,
  'multiple_choice',
  'Direitos Humanos — Fundamentos Teóricos A doutrina dos direitos humanos apresenta diferentes correntes teóricas acerca de seu fundamento jurídico, as quais se desenvolveram em momentos históricos distintos e refletem concepções diversas sobre a relação entre indivíduo, Estado e ordem jurídica. Autores como Norberto Bobbio analisam essa evolução a partir do diálogo entre filosofia, constitucionalismo e direito internacional, destacando que tais correntes não se excluem necessariamente, mas revelam diferentes etapas de compreensão e positivação dos direitos humanos. Considerando esse panorama teórico, assinale a alternativa correta.',
  'A',
  'A evolução histórica dos direitos humanos pode ser compreendida a partir de três grandes correntes teóricas. A primeira delas é a corrente jusnaturalista, segundo a qual os direitos humanos são inerentes à própria condição humana. Nessa perspectiva, os direitos não dependem do reconhecimento estatal para existir; decorrem da razão divina ou da razão humana e são universais, válidos para todos os indivíduos em qualquer tempo ou lugar. Trata-se da fase em que os direitos humanos eram concebidos como direitos naturais. Com as revoluções liberais do século XVIII, especialmente a Revolução Francesa e a Independência dos Estados Unidos, esses direitos passaram a ser positivados em declarações e constituições nacionais. Surge, então, a corrente juspositivista nacionalista, que entende que o fundamento jurídico dos direitos humanos encontra-se na Constituição de cada Estado. No século XX, sobretudo após a Segunda Guerra Mundial, os direitos humanos passam a ser positivados em tratados e convenções internacionais, como a Declaração Universal de 1948, consolidando a corrente juspositivista internacionalista, segundo a qual o fundamento dos direitos humanos está no direito internacional. O pensamento de Bobbio sintetiza essa trajetória: dos direitos naturais universais, à positivação constitucional interna, culminando na positivação universal por meio do direito internacional.'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000019-0000-0000-0000-000000000000', 'A', 'A corrente jusnaturalista sustenta que os direitos humanos são inerentes à própria condição humana, decorrendo da razão divina ou da razão humana, existindo independentemente de reconhecimento estatal, sendo posteriormente positivados em Constituições nacionais e, mais tarde, em instrumentos internacionais.', '', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000019-0000-0000-0000-000000000000', 'B', 'A corrente juspositivista nacionalista afirma que os direitos humanos existem apenas quando reconhecidos pelo direito internacional, sendo irrelevante sua incorporação em Constituições nacionais, pois seu fundamento reside exclusivamente na ordem jurídica global.', '', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000019-0000-0000-0000-000000000000', 'C', 'A corrente juspositivista internacionalista entende que os direitos humanos derivam diretamente da razão humana e possuem fundamento metafísico, sendo desnecessária sua positivação em tratados ou convenções internacionais.', '', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000019-0000-0000-0000-000000000000', 'D', 'A teoria jusnaturalista rejeita a universalidade dos direitos humanos, sustentando que tais direitos são construções culturais variáveis, dependentes exclusivamente da legislação interna de cada Estado.', '', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000019-0000-0000-0000-000000000000', 'E', 'As três correntes defendem que os direitos humanos possuem fundamento exclusivamente constitucional, inexistindo relevância do direito internacional ou de fundamentos filosóficos anteriores à positivação estatal.', '', false);
