-- Q20: Sistemas Internacionais de Proteção aos Direitos Humanos (Si
INSERT INTO questions (id, topic_id, question_number, question_type, statement, correct_answer, detailed_explanation)
VALUES (
  '00000020-0000-0000-0000-000000000000',
  (SELECT id FROM topics WHERE name = 'Sistemas Internacionais de Proteção'),
  20,
  'multiple_choice',
  'Sistemas Internacionais de Proteção aos Direitos Humanos (Sistema Global) No âmbito do sistema global de proteção dos Direitos Humanos, destacam-se a Declaração Universal dos Direitos Humanos (1948), o Pacto Internacional dos Direitos Civis e Políticos (PIDCP) e o Pacto Internacional dos Direitos Econômicos, Sociais e Culturais (PIDESC). Considerando a natureza jurídica desses instrumentos e os mecanismos de controle por eles previstos, assinale a alternativa correta:',
  'B',
  'A Declaração Universal dos Direitos Humanos, adotada em 1948 pela Assembleia Geral da ONU, não é um tratado internacional, mas uma resolução com relevante força política e influência normativa, servindo de base para a construção posterior de instrumentos vinculantes. Já o Pacto Internacional dos Direitos Civis e Políticos (PIDCP) e o Pacto Internacional dos Direitos Econômicos, Sociais e Culturais (PIDESC) são tratados internacionais obrigatórios para os Estados que os ratificam. O PIDCP prevê, além de relatórios estatais e comunicações interestatais, a possibilidade de petições individuais mediante adesão ao seu Protocolo Facultativo. O PIDESC, por sua vez, também estabelece o sistema de relatórios estatais e admite comunicações interestatais, petições individuais e investigações quando o Estado ratifica o respectivo Protocolo Facultativo. Essa diferenciação demonstra a evolução do sistema global de proteção dos direitos humanos, que combina instrumentos declaratórios com tratados vinculantes e mecanismos progressivos de supervisão internacional. 21. Tribunal Penal Internacional e Estatuto de Roma O Estatuto de Roma, promulgado no Brasil pelo Decreto nº 4.388/2002, instituiu o Tribunal Penal Internacional (TPI), estabelecendo sua natureza, competência e forma de atuação no âmbito da comunidade internacional. Considerando as disposições do Estatuto de Roma e a estrutura do Tribunal Penal Internacional, assinale a alternativa correta: A) O Tribunal Penal Internacional é órgão vinculado diretamente à Organização das Nações Unidas, possuindo competência automática e obrigatória sobre todos os Estados membros da ONU, independentemente de ratificação do Estatuto de Roma, exercendo jurisdição substitutiva às jurisdições penais nacionais. B) O Tribunal Penal Internacional é uma instituição permanente, com jurisdição sobre pessoas responsáveis por crimes de maior gravidade com alcance internacional, exercendo competência de natureza complementar às jurisdições penais nacionais, nos termos do Estatuto de Roma. C) O Tribunal Penal Internacional foi criado como órgão temporário para julgar crimes cometidos exclusivamente após conflitos armados internacionais, possuindo competência restrita a Estados que expressem concordância caso a caso com sua atuação. D) O Tribunal Penal Internacional possui competência para julgar Estados soberanos por violações de direitos humanos, podendo impor sanções políticas e econômicas diretamente aos entes estatais que descumprirem normas internacionais. E) O Tribunal Penal Internacional atua como instância recursal das decisões proferidas pelos tribunais nacionais em matéria penal, podendo revisar sentenças condenatórias ou absolutórias sempre que houver alegação de violação de direitos fundamentais. Resolução Alternativa Correta: B A alternativa correta é a letra B, pois reproduz adequadamente o conteúdo do art. 1º do Estatuto de Roma, segundo o qual o Tribunal Penal Internacional é uma instituição permanente, com jurisdição sobre pessoas responsáveis pelos crimes de maior gravidade com alcance internacional, exercendo competência complementar às jurisdições penais nacionais. Análise das Alternativas Alternativa A: Incorreta. O Tribunal Penal Internacional não é órgão da ONU, embora mantenha relação de cooperação com ela. Além disso, sua competência não é automática para todos os Estados membros da ONU, pois depende de ratificação do Estatuto de Roma ou de situações específicas previstas no próprio Estatuto. Também não exerce jurisdição substitutiva, mas complementar. Alternativa B: Correta. O Estatuto de Roma estabelece que o TPI é instituição permanente e que sua jurisdição incide sobre pessoas responsáveis por crimes de maior gravidade com alcance internacional, sendo complementar às jurisdições penais nacionais, ou seja, atua quando o Estado não pode ou não quer exercer adequadamente sua jurisdição. Alternativa C: Incorreta. O TPI não é tribunal temporário, mas permanente. Além disso, sua competência não se limita a conflitos armados internacionais, abrangendo também outros crimes previstos no Estatuto, e não depende de concordância pontual caso a caso, mas de critérios estabelecidos no próprio Estatuto. Alternativa D: Incorreta. O TPI não julga Estados soberanos, mas pessoas físicas. Sua jurisdição é penal individual, não sendo competente para impor sanções políticas ou econômicas a Estados. Alternativa E: Incorreta. O Tribunal Penal Internacional não funciona como instância recursal das decisões dos tribunais nacionais. Ele não revisa sentenças nacionais; atua de forma complementar quando verificada a incapacidade ou falta de disposição do Estado em processar seriamente os responsáveis. Explicação Detalhada O Estatuto de Roma, adotado em 1998 e promulgado no Brasil pelo Decreto nº 4.388/2002, criou o Tribunal Penal Internacional como uma instituição permanente destinada a julgar pessoas responsáveis por crimes de maior gravidade com alcance internacional. O art. 1º do Estatuto est'
);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000020-0000-0000-0000-000000000000', 'A', 'A Declaração Universal dos Direitos Humanos, por ter sido aprovada pela Assembleia Geral da ONU, possui natureza jurídica de tratado internacional vinculante; o PIDCP e o PIDESC, por sua vez, admitem apenas relatórios estatais como mecanismos de controle, não sendo possível a apresentação de petições individuais em nenhum caso.', 'O neoprocessualismo rompe com a ideia de neutralidade formal do processo. A Constituição passa a orientar a interpretação das normas processuais. O juiz não está limitado à literalidade formal quando a efetividade dos direitos fundamentais está em jogo.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000020-0000-0000-0000-000000000000', 'B', 'A Declaração Universal dos Direitos Humanos, embora não seja formalmente um tratado, possui força jurídica equivalente à dos Pactos Internacionais; o PIDCP e o PIDESC estabelecem mecanismos idênticos de controle, prevendo automaticamente petições individuais e investigações independentemente de protocolo facultativo.', 'Reflete a essência do formalismo-valorativo: • centralidade da Constituição; • interpretação conforme direitos fundamentais; • busca de efetividade; • possibilidade de técnicas processuais adequadas ao caso concreto.', true);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000020-0000-0000-0000-000000000000', 'C', 'A Declaração Universal dos Direitos Humanos constitui tratado internacional com mecanismos próprios de supervisão; o PIDCP e o PIDESC, embora tratados, não admitem qualquer forma de petição individual, limitando-se à cooperação diplomática entre Estados.', 'O neoprocessualismo não autoriza supressão de garantias processuais. Efetividade não elimina contraditório, ampla defesa ou sistema recursal. Ao contrário, reforça a necessidade de fundamentação qualificada.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000020-0000-0000-0000-000000000000', 'D', 'A Declaração Universal dos Direitos Humanos é tratado internacional que depende de ratificação pelos Estados; o PIDCP e o PIDESC admitem apenas comunicações interestatais, sendo vedada, em qualquer hipótese, a apresentação de petições individuais ou a realização de investigações.', 'O art. 20 da LINDB proíbe decisões baseadas exclusivamente em valores abstratos sem consideração das consequências práticas. O neoprocessualismo exige fundamentação robusta, não voluntarismo judicial.', false);
INSERT INTO alternatives (question_id, letter, text, analysis, is_correct)
VALUES ('00000020-0000-0000-0000-000000000000', 'E', 'A Declaração Universal dos Direitos Humanos não possui natureza de tratado internacional, mas sim de resolução da Assembleia Geral da ONU; o PIDCP prevê relatórios estatais, comunicações interestatais e petições individuais mediante Protocolo Facultativo; e o PIDESC estabelece relatórios estatais, admitindo comunicações interestatais, petições individuais e investigações quando previsto em seu Protocolo Facultativo.', 'A constitucionalização do processo vai além da previsão expressa de garantias. Ela implica releitura sistemática de todo o direito processual à luz da Constituição.', false);
